UPDATE ENQ_MAIN
SET ENQ_NO = @ENQ_NO
WHERE ENQ_ID = @ENQ_ID and sup_id=@g_sup_id;

SELECT GRP_SDATE AS F_DATE ,grp_num as people_num ,grp_wait_days day_num ,
  cast(round(grp_num/2.0+0.4,0) as int) dub_num

FROM GRP_MAIN WHERE GRP_ID=@GRP_ID;


-- 新询价单默认值		
SELECT GRP_CODE+'/Q'+RIGHT('00000'+CONVERT(VARCHAR,ISNULL(AA,1)),3) ENQ_NO
	FROM GRP_MAIN		A
	LEFT JOIN (
			SELECT COUNT(*)+1 AA,GRP_ID FROM ENQ_MAIN 
				WHERE GRP_ID=@GRP_ID
				GROUP BY GRP_ID

	) B ON A.GRP_ID=B.GRP_ID 
	WHERE A.GRP_ID=@GRP_ID AND SUP_ID=@G_SUP_ID AND @EWA_MTYPE='N' ;



