function aa() {
  var tb = $X('EWA_MG_' + '@SYS_FRAME_UNID');
  for (var i = 0; i < tb.rows.length; i++) {
    var row = tb.rows[i];
    for (var ia = 0; ia < row.cells.length; ia++) {
      var cell = row.cells[ia];
      if (cell.id.indexOf('MGB') > -1) {
        cell.style.textAlign = 'left';
      }
      if (cell == null || cell.id == null || cell.id.indexOf('MGC') != 0) {
        continue;
      }
      if (cell.innerText != null && cell.innerText != '') {
        cell.onclick = function() {
          //bb(this);
        }
      }
    }
  }
}
var edit = null;
function bb(obj) {
  if (!edit) {
    edit = document.createElement('input');
    edit.style.width = '100%';

  }
  edit.style.display = '';
  edit.value = GetInnerText(obj).trim();
  obj.childNodes[0].style.display = 'none';
  obj.appendChild(edit);
  edit.focus();

}

