    var loc0 = o.offset();
    o.css("transform", "scale(0.75)");
    var loc = o.offset();
    o.css({
      'margin-left': loc0.left - loc.left,
      'margin-top': loc0.top - loc.top
    });
  }
  $X('X').style.display = 'none';
  $X('Y').style.display = 'none';
  if ('@not_other' == '') {
    // aa();
    //show1(@enq_ID,@grp_id);
    show2(@enq_ID, @grp_id);
    show3(@grp_id);
    show4(@enq_ID, @grp_id);
