function getHtml() {
    var ajax = new EWA_AjaxClass();
    ajax.AddParameter("grp_id", '@grp_id');
    ajax.AddParameter("enq_ID", '@enq_id');
    ajax.PostNew('@ewa.cp/ewa?xmlname=/business/enq/price.xml&ITEMNAME=ENQ_LIST', function() {
        if (!ajax.IsRunEnd()) {
            return;
        }
        html = ajax.GetRst();

    });


}

function reOpen(grpId, enqId) {
    if (enqId == null || enqId == '') {
        alert('该团还未提交，无需重新开放！');
        return;
    }
    var html;
    var paras = [];
    paras[0] = {
        Name: 'grp_id',
        Value: grpId
    };
    paras[1] = {
        Name: 'enq_id',
        Value: enqId
    };
    var ajax = new EWA_AjaxClass();
    ajax.AddParameter("grp_id", "@grp_id");
    ajax.AddParameter("enq_ID", enqId);
    ajax.PostNew('@ewa.cp/ewa?xmlname=/business/enq/price.xml&ITEMNAME=ENQ_LIST', function() {
        if (!ajax.IsRunEnd()) {
            return;
        }
        html = ajax.GetRst();
        paras[2] = {
            Name: 'html',
            Value: html
        };

        EWA.F.FOS['@SYS_FRAME_UNID'].DoAction(this, 'ExtendAction0', '你确认要重新开放么', '', paras);
    });
}

