var reg = /^[0-9]*\.?[0-9]*$/;

function aa() {
    var tb = $X('EWA_MG_' + '@SYS_FRAME_UNID');
    for (var i = 0; i < tb.rows.length; i++) {
        var row = tb.rows[i];
        for (var ia = 0; ia < row.cells.length; ia++) {
            var cell = row.cells[ia];
            if (cell.id.indexOf('MGB') > -1) {
                cell.style.textAlign = 'left';
            }
            if (cell == null || cell.id == null || cell.id.indexOf('MGC') != 0) {
                continue;
            }
            if (cell.innerText != null && cell.innerText != '') {
                cell.onclick = function() {
                    bb(this);
                }
            }
        }
    }
}
var edit = null;

function bb(obj) {
    if (!edit) {
        edit = document.createElement('input');
        edit.style.width = '100%';


        edit.onmousedown = function() {
            edit.focus();
        }

        edit.onblur = function() {
            if (!reg.test(edit.value.split("/")[0].replace(/,/g, ''))) {
                alert('/之前的价格必须是数字');
                return;
            }

            this.style.display = 'none';
            this.parentNode.childNodes[0].style.display = '';
            var id1 = obj.attributes["id1"].nodeValue;
            var ajax = new EWA_AjaxClass();
            ajax.AddParameter("enq_JNY_ID", id1.split("_")[1].split(";")[0]);
            ajax.AddParameter("SER_ID", id1.split("_")[0]);
            ajax.AddParameter("enq_JNY_PRICE", edit.value.split("/")[0]);
            ajax.AddParameter("enq_ID", '@enq_id');
            ajax.AddParameter("coin_key", edit.value.split("/")[1]);
            ajax.AddParameter("sup_down_ID", id1.split("_")[1].split(";")[1]);
            ajax.PostNew('@EWA.CP/EWA_STYLE/cgi-bin/?XMLNAME=/business/enq/price.xml&ITEMNAME=enq_JNY_SER_AJAX.ListFrame.View', function() {
                if (!ajax.IsRunEnd()) {
                    return;
                }
                //alert(ajax.GetRst());
                show1('@enq_ID', '@grp_id');
                show2('@enq_ID', '@grp_id');
                show3('@grp_id');
                show4('@enq_ID', '@grp_id');
            });
            this.parentNode.childNodes[0].innerText = edit.value
            edit = null;
        }
    }
    edit.style.display = '';
    edit.value = GetInnerText(obj).trim();
    obj.childNodes[0].style.display = 'none';
    obj.appendChild(edit);
    edit.focus();

}

