function change() {
    var a = getchecked();
    var u = '@ewa.cp/ewa?xmlname=@xmlname&ITEMNAME=@itemname&ewa_action=getremark&EWA_AJAX=JSON&key=' + a;
    $J(u, (str) => {
        $X('DAY_REMARK').value = '';
        $X('REMARK').value = '';
        for (var i = 0; i < str.length; i++) {
            $X('DAY_REMARK').value += str[i].ed + ' ' + str[i].enq_jny_ob2 + ';' + '\r\n';
            $X('REMARK').value += str[i].ed + ' ' + str[i].enq_jny_content + ';' + '\r\n';
        }
        // gethtml();
    });
}


function getchecked() {
    var val = '';
    var ck = document.getElementById('ENQ_JNY_ID');
    var cks = ck.getElementsByTagName('input');
    for (var i = 0; i < cks.length; i++) {
        if (cks[i].type == 'checkbox' && cks[i].checked) {
            if (val == '') {
                val += cks[i].value
            } else {
                val += ',' + cks[i].value
            }

        }
    }
    return val;
}

function gethtml() {
    //获取合同文本，内容不对
    var u = '@ewa.cp/ewa?xmlname=/business/enq/price.xml&ITEMNAME=ENQ_OP_LIST&ENQ_ID=@ENQ_ID&SER_IDS=@SER_IDS&ENQ_JNY_ID=@ENQ_JNY_ID';
    var ajax = new EWA_AjaxClass();
    ajax.PostNew(u, function() {
        if (!ajax.IsRunEnd()) {
            return;
        }
        $X('HTML').value = ajax.GetRst();
    });
}

