    }
}

var selectedAllCheckbox = {
    init: function(id, isRedraw) {
        var s = "<span><input type='checkbox' onclick=\"selectedAllCheckbox.selAll('" +
            id + "',this)\" id='CK_SEL_ALL_" +
            id + "'><label for='CK_SEL_ALL_" +
            id + "'>全选</label></span>";
        if (isRedraw == "1") {
            $("#" + id).parent().prev().find(".ewa_d1").css("width", "30px").after(s);
        } else {
            $("#" + id).parent().next().prepend(s);
        }
        this.initCks(id);
        selectedAllCheckbox.selSig($("input[type='checkbox'][name='" + id + "']")[0]);
    },
    initArr: function(ids, isRedraw) {
        for (var i = 0; i < ids.length; i++) {
            this.init(ids[i], isRedraw);
        }
    },
    initCks: function(id) {
        $("input[type='checkbox'][name='" + id + "']").bind("click",
            function() {
                selectedAllCheckbox.selSig(this);
            }
        );
    },
    selAll: function(id, obj) {
        if (obj.checked) {
            $("input[type='checkbox'][name='" + id + "']").each(
                function() {
                    this.checked = true;
                }
            );
        } else {
            $("input[type='checkbox'][name='" + id + "']").each(
                function() {
                    this.checked = false;
                }
            );
        }
        if (this.selAfter) {
            this.selAfter(id, obj);
        }
    },
    selSig: function(obj) {
        var n = $(obj).attr("name");
        var objs = $("input[type='checkbox'][name='" + n + "']");
        var ckd = 0;
        var uckd = 0;
        for (var i = 0; i < objs.length; i++) {
            if (objs[i].checked) {
                ckd++;
            } else {
                uckd++;
            }
        }
        if (objs.length == ckd && ckd > 0) {
            $("#CK_SEL_ALL_" + n)[0].checked = true;
        } else {
            $("#CK_SEL_ALL_" + n)[0].checked = false;
        }
    },
    selAfter: function(id, obj) {
        //全选后执行
    }
};

(function() {
    selectedAllCheckbox.selAfter = function(id) {
        if (id == "ENQ_JNY_ID") {
            change();
        }
    }
    selectedAllCheckbox.initArr(["SER_IDS", "ENQ_JNY_ID"], "@EWA_REDRAW");
    if ('@EWA_MTYPE' == 'M') {
        change();
    }
    if ('@pkg' == '1') {
        $("#CK_SEL_ALL_SER_IDS")[0].click();
        $("#CK_SEL_ALL_ENQ_JNY_ID")[0].click();
        $X("SUP_TYPE").value = "SUP_GROUND_MASTER";
    }


    if ('@EWA_MTYPE' == 'M') {
        //给组件添加默认值
        $("#ENQ_OP_CONTACT").attr("data-old-value", "@ENQ_OP_CONTACT");
        $("#ENQ_OP_SUP_ACC_ID").attr("data-old-value", "@ENQ_OP_SUP_ACC_ID");

        change();
    } else if ("@SER_IDS") {
        change();
    }
})();

