var enq_map = {};

function show_enq_op_main(chk) {
    if (chk.checked) {
        $('#EWA_MG_@SYS_FRAME_UNID .enq-op-main').show();
    } else {
        $('#EWA_MG_@SYS_FRAME_UNID .enq-op-main').hide();
