}

function loadEnqOpMain_a() {
    var u = '@EWA.CP/EWA_STYLE/cgi-bin/?xmlname=business/group/fin.xml&itemname=a1&ewa_ajax=json&ewa_action=loadEnqOpMain&grp_id=@grp_id&enq_id=@enq_id';
    $J(u, loadEnqOpMaina1);
}


function loadEnqOpMaina1(datas) {
    for (var i = 0; i < datas.length; i++) {
        var d = datas[i];
        var id1 = d.SER_ID + '_' + d.enq_jny_id + ';' + d.COIN_ID;
        // console.log(id1);
        var p = d.enq_jny_price_sup * 1;
        var c = 'line-height:17px;';
        if (p > d.enq_jny_price * 1) {
            c = 'color:red;';
        } else if (p < d.enq_jny_price * 1) {
            c = 'color:green;';
        }
        var title = "询价单：" + d.ENQ_OP_ID + "\n供应商：" + d.sup_name;

        var op_id = d.ENQ_OP_ID;

        var t = '<div class="enq-op-main" title="' + title + '" op_id="' + op_id +
            '" onmouseover="show_rel(this);" onmouseout="show_rela(this)" onclick="getEnqInfo(' + d.ENQ_OP_ID + ',this)" style="' + c + '" id="enqopid' + d.ENQ_OP_ID + '">[询]' + p +
            ' x ' + (d.vnum * 1) + ' = ' + p * d.vnum + '/' + d.coin_key + '</div>';
        $('td[id1="' + id1 + '"]').append(t);
    }
    findunenq();
}
