    })
}


//价格发生变化标注出来
function change() {
    var s = [];
    var u = '@EWA.CP/EWA_STYLE/cgi-bin/?XMLNAME=/business/enq/price.xml&ITEMNAME=enq_JNY_SER_AJAX.ListFrame.View&ewa_action=getchange&EWA_AJAX=JSON&enq_id=@enq_id';

    var ajax = new EWA_AjaxClass();
    $J(u, change1);
}

function change1(datas) {
    var objs = $X('EWA_MG_@SYS_FRAME_UNID').getElementsByTagName('td');
    var o = {};
    for (var i = 0; i < objs.length; i++) {
        var o1 = objs[i];
        if (o1.id.indexOf('MGC_') > -1) {
            o[o1.getAttribute('id1')] = o1.getElementsByTagName('div')[0];
        }
    }

    for (var i = 0; i < datas.length; i++) {
        var d = datas[i];
        var sid = d.ser_id;
        var ejid = d.enq_jny_id;
        var sdid = d.sup_down_id;
        let coinId = d.coin_id;

        var id1 = sid + '_' + ejid + ';' + sdid + ";" + coinId;
        var dp = d.dprice;
        //alert(id1);
        if (o[id1]) {
            //alert(dp);
            if (dp < 0) {

                o[id1].style.color = 'green';
            } else {
                o[id1].style.color = 'red';
            }
            o[id1].title = '数据库价格：' + d.spc;
        }
    }
}

//判断数组是否在字符串中
function inarray(obj, arr) {
    if (typeof obj == 'string') {
        for (var i in arr) {
            if (arr[i] == obj) {
                return true;
            }
        }
    }
    return false;
}

