function getPacthtml() {
    var u = '@ewa.cp/ewa?XMLNAME=@XMLNAME&ITEMNAME=ENQ_OP_MAIN_SUB_FILE&ENQ_ID=@ENQ_ID&SER_IDS=@SER_IDS&ENQ_JNY_IDS=@ENQ_JNY_ID&SUP_ID=@SUP_ID&ENQ_OP_ID=@ENQ_OP_ID&grp_id=@GRP_ID';
    var ajax = new EWA_AjaxClass();
    ajax.PostNew(u,
        function() {
            if (!ajax.IsRunEnd()) {
                return;
            }
            var htm = ajax.GetRst();
            var obj = $(htm).find('table').attr("border", "1").removeAttr('onmouseover')
                .attr('bordercolor', 'black').css('border-collapse', 'collapse');
            var rp = obj.find("a").parent().html();
            // console.log(rp);
            var f_html = obj.html().replace(rp, "天数/城市");
            // console.log(f_html);
            $X('PACT_HTML').value = f_html;

        });
}
(function() {
    let SUB_SUP_ID_NUM = "@SUB_SUP_ID_NUM";
