})();

Set.Sql:
UPDATE ENQ_OP_MAIN SET CONFIRM_NO=@CONFIRM_NO , CONFIRM_MEMO=@CONFIRM_NO , CONFIRM_TIME=@SYS_DATE , CONFIRM_ADM_ID=@G_ADM_ID , STATE='ENQ_FIN' ,PACT_HTML=@PACT_HTML
WHERE ENQ_OP_ID = @ENQ_OP_ID and own_sup_id=@g_sup_id;
IF NOT EXISTS(SELECT * FROM CURRENCY_FILE WHERE [STATE]='USED' AND REF_TYPE = 'ENQ_OP_MAIN' AND REF_ID = @ENQ_OP_ID AND SUP_ID = @G_SUP_ID ) INSERT INTO CURRENCY_FILE (REF_ID,REF_TYPE,SUP_ID,FILE_TYPE, CURRENCY_REMARK ,CURRENCY_SYNC_UNID,ADM_ID,RELATE_SUP_ID ,PIC_PHY_PATH,PIC_MD5,CURRENCY_EXT,CURRENCY_OB1,CURRENCY_OB2,GRP_ID) SELECT ENQ_OP_ID, 'ENQ_OP_MAIN',@G_SUP_ID,'PACT1','采购合同' ,GETDATE(), A.ADM_ID,A.SUP_ID ,PIC_PHY_PATH,PIC_MD5,PIC_EXT,'采购合同-'+SUP_NAME+'['+CAST(ENQ_OP_ID AS VARCHAR(10))+'].'+ISNULL(PIC_EXT,''),PIC_LEN ,C.GRP_ID FROM ENQ_OP_MAIN A INNER JOIN SUP_MAIN B ON A.SUP_ID=B.SUP_ID INNER JOIN V_GRP_MAIN C ON A.ENQ_ID=C.ENQ_ID WHERE ENQ_OP_ID=@ENQ_OP_ID AND ISNULL(PIC_PHY_PATH,'')<>''
ELSE
UPDATE CURRENCY_FILE SET CURRENCY_FILE.PIC_PHY_PATH=A.PIC_PHY_PATH , CURRENCY_FILE.PIC_MD5=A.PIC_MD5 , CURRENCY_EXT=PIC_EXT ,CURRENCY_OB1='采购合同-'+SUP_NAME+'['+CAST(ENQ_OP_ID AS VARCHAR(10))+'].'+ISNULL(PIC_EXT,'') , CURRENCY_OB2=PIC_LEN FROM ENQ_OP_MAIN A INNER JOIN SUP_MAIN B ON A.SUP_ID=B.SUP_ID WHERE ENQ_OP_ID = @ENQ_OP_ID AND CURRENCY_FILE.[STATE]='USED' AND CURRENCY_FILE.REF_TYPE = 'ENQ_OP_MAIN' AND CURRENCY_FILE.REF_ID = @ENQ_OP_ID;

Set.Bottom:
//GRP_SER_SP_MAIN.LF.M
(function() {
    let ewa = EWA.F.FOS['@SYS_FRAME_UNID'];
    ewa.ReloadAfter = function(httpReferer) {
        if (httpReferer) { // 来源Frame的url，多出现在新增或修改后调用
            let uref = new EWA_UrlClass(httpReferer);
            let mtype = uref.GetParameter("EWA_MTYPE");
            let refXml = uref.GetParameter("XMLNAME");
            let refItem = uref.GetParameter("ITEMNAME");

            // frame定义了SQLSet的name以outParams开头的SELECT输出语句（大小写无关）
            let outParams = ewa.outParams;
            if (outParams && outParams.length > 0) {
                let outParam0 = outParams[0];
            }
        }
        // ewa.Merge('fromId', 'toId'); //合并单元格
        // let exp="@@aa <h1>@@bb</h1> <div>@@cc</div>";
        // ewa.MergeExp('toId', exp); //合并多个单元格


    };
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        let cntTd = newTr.cells[0]; //新行的td
        let u1 = new EWA_UrlClass(this.Url);
        u1.AddParameter("ITEMNAME", "GRP_SER_SP.ListFrame.MODIFY"); //避免sys_frame_unid冲突
        u1.AddParameter("gssm_id", key);

        // 通过ajax加载内容
        let ajaxUrl = u1.GetUrl();
        $Install(ajaxUrl, cntTd, function() {
            console.log('install ok');
        });
    });
    ewa.ext_AddNew = function() {
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        u1.AddParameter("EWA_MTYPE", "N");
        u1.AddParameter("ewa_in_dialog", 1);
        let paras = u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlName', 'GRP_SER_SP_MAIN.F.NM', false, paras);
    };

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }

    ewa.changeTabShow = function(tab){
        if ($(tab).hasClass('EWA_GROUP_CNT_TOP1')) {
            return;
        }
        var last = $(tab).parent().find(".EWA_GROUP_CNT_TOP1");
        var last_id = last.attr('rid');
        last.removeClass("EWA_GROUP_CNT_TOP1").addClass("EWA_GROUP_CNT_TOP");
        $('#' + last_id).hide();

        var this_id = $(tab).attr('rid');
        $(tab).addClass("EWA_GROUP_CNT_TOP1").removeClass("EWA_GROUP_CNT_TOP");
        $('#' + this_id).show();
    }

    function initBox() {
        let last_td_id = 'box_@sys_frame_unid';
        let s = `<div>
        <div rid='${last_td_id}_0' onclick='EWA.F.FOS["@sys_frame_unid"].changeTabShow(this)' class='EWA_GROUP_CNT_TOP1'>变更单</div>
        <div rid='${last_td_id}_1' onclick='EWA.F.FOS["@sys_frame_unid"].changeTabShow(this)' class='EWA_GROUP_CNT_TOP'>变更明细</div>
        <div style='clear:both'></div>
    </div>`;
        let html = s + `<div class='box0' id="${last_td_id}_0"></div>
        <div style="display:none" class='box1' id="${last_td_id}_1"></div>`;
        let obj = $("<div style='min-height:303px;'>" + html + "</div>");
        $('#EWA_RESHOW_@sys_frame_unid').parent().append(obj);
        obj.find('.box0').append($('#EWA_RESHOW_@sys_frame_unid'));

        let u = new EWA_UrlClass(ewa.Url);
        u.AddParameter("ITEMNAME", "GRP_SER_SP.ListFrame.modify");
        $Install(u, obj.find('.box1'))
    }
    // 执行刷新后事件
    function init() {
        if ("@initBox") {
            initBox();
        }
        ewa.ReloadAfter();
    }
    init();
})();

Set.Sql:
SELECT '流程已经开始，不能删除' AS EWA_ERR_OUT from GRP_SER_SP_MAIN where GSSM_ID = @GSSM_ID and (isnull(GSSM_FLOW,'') not in ('','EOM_CHG_START','EOM_CHG_DENY')) ;
SELECT '团已经关闭,不能进行操作' AS EWA_ERR_OUT from grp_main where grp_id=@grp_id and CLAC_STATUS IN('FINALLY_CLOSE','CLOSE') ;
SELECT distinct '已生成过支出计划,不能删除' EWA_ERR_OUT FROM GRP_FIN_TYPE a inner join GRP_SER_SP b on b.GRP_SER_SP_ID = a.GRP_FIN_TYPE_REFID and a.GRP_FIN_TYPE_FROM ='GRP_SER_SP' and b.GSSM_ID = @GSSM_ID ;
UPDATE GRP_SER_SP_MAIN SET GSSM_STATUS='DEL' WHERE GSSM_ID = @GSSM_ID AND SUP_ID = @G_SUP_ID ; INSERT INTO GRP_SER_SP_DEL_LOG( GRP_SER_SP_ID, GRP_ID, ENQ_ID, ENQ_JNY_ID, SER_TAG, GRP_SER_SP_NAME, GRP_SER_SP_PRICE , COIN_ID, GRP_SER_SP_REMARK, GRP_SER_SP_TYPE, GRP_SER_SP_NUM, SUP_ID, ADM_ID , CREATE_TIME, GRP_SER_SP_OB1, GRP_SER_SP_OB2, GRP_SER_SP_OB3, SUP_DOWN_ID , GRP_SER_SP_FROM, GRP_SER_SP_REFID, GRP_SER_SP_IMG, IMG_LEN, IMG_EXT , IMG_MD5, LAST_EML_ID, FRO_ENQ_JNY_SER_SUB_ID, FRO_TYPE, FRO_SUB_NUM , FRO_SER_KEY0, FRO_SER_KEY1, FRO_SER_KEY2, FRO_SER_CITY_ID, FRO_ENQ_JNY_DATE , FRO_ENQ_JNY_DAY, GSSM_ID, FRO_SER_CONN_ID, FRO_ENQ_OP_SUB_ID , FRO_ENQ_OP_SUB_ID_INDEX, FRO_ENQ_JNY_SER_SUB_INDEX , DEL_DATE, DEL_ADM_ID ) SELECT GRP_SER_SP_ID, GRP_ID, ENQ_ID, ENQ_JNY_ID, SER_TAG, GRP_SER_SP_NAME, GRP_SER_SP_PRICE , COIN_ID, GRP_SER_SP_REMARK, GRP_SER_SP_TYPE, GRP_SER_SP_NUM, SUP_ID, ADM_ID , CREATE_TIME, GRP_SER_SP_OB1, GRP_SER_SP_OB2, GRP_SER_SP_OB3, SUP_DOWN_ID , GRP_SER_SP_FROM, GRP_SER_SP_REFID, GRP_SER_SP_IMG, IMG_LEN, IMG_EXT , IMG_MD5, LAST_EML_ID, FRO_ENQ_JNY_SER_SUB_ID, FRO_TYPE, FRO_SUB_NUM , FRO_SER_KEY0, FRO_SER_KEY1, FRO_SER_KEY2, FRO_SER_CITY_ID, FRO_ENQ_JNY_DATE , FRO_ENQ_JNY_DAY, GSSM_ID, FRO_SER_CONN_ID, FRO_ENQ_OP_SUB_ID , FRO_ENQ_OP_SUB_ID_INDEX, FRO_ENQ_JNY_SER_SUB_INDEX , @SYS_DATE, @G_ADM_ID from GRP_SER_SP WHERE GSSM_ID = @GSSM_ID and SUP_ID = @g_sup_id ;
DELETE FROM GRP_SER_SP WHERE GSSM_ID = @GSSM_ID and SUP_ID = @g_sup_id ;

select '已经确认过了，无需重复操作' as EWA_ERR_OUT from GRP_SER_SP_main where gssm_id = @gssm_id and CONFIRM_SUP_ID > 0 ;
select '没有操作权限，供应商编号不对' as EWA_ERR_OUT where not exists( select 1 from GRP_SER_SP_main where (sup_down_id = @g_sup_id or sup_id = @g_sup_id) -- 双方都可以操作 and gssm_id = @gssm_id );
select '请先完成审批流程' as EWA_ERR_OUT where not exists( select 1 from GRP_SER_SP_main where (sup_down_id = @g_sup_id or sup_id = @g_sup_id) -- 双方都可以操作 and gssm_id = @gssm_id and GSSM_FLOW in ('EOM_CHG_SUPPLY','EOM_CHG_END') );
select 'GRP_SER_SP_MAIN' wkFlowId, 'EOM_CHG_SUPPLY' curUnid, 'EOM_CHG_END' nextUnid -- 替供应商点击确认按钮后，自动完成审批流程 from GRP_SER_SP_main where sup_id = @g_sup_id and gssm_id = @gssm_id and GSSM_FLOW='EOM_CHG_SUPPLY' ;
-- ewa_test @curUnid='EOM_CHG_SUPPLY' select ewa_func.flowNext(@wkFlowId, @curUnid, @curUnid, @nextUnid, @gssm_id, rv) from GRP_SER_SP_main where sup_id = @g_sup_id and gssm_id = @gssm_id and GSSM_FLOW='EOM_CHG_SUPPLY' -- ewa_test ;
exec PR_GRP_SER_SP_CONFIRM @GSSM_ID, @g_adm_id, @g_sup_id,'EOM_CHG_END';

-- enter your sql
-- 备份确认sql，改用存储过程了 update GRP_SER_SP_main set CONFIRM_SUP_ID = @g_sup_id , CONFIRM_TIME = @sys_date , CONFIRM_ADM_ID = @g_adm_id where (sup_down_id = @g_sup_id or sup_id = @g_sup_id) -- 双方都可以操作 and CONFIRM_SUP_ID is null and gssm_id = @gssm_id; ;
update enq_op_main_sub set enq_op_main_sub.sub_num = case when fro_type ='DELETE' then 0 when fro_type ='INSERT' then a.FRO_SUB_NUM when fro_type = 'UPDATE' then enq_op_main_sub.sub_num + a.GRP_SER_SP_NUM_REAL end , enq_op_main_sub.enq_jny_price = case when fro_type = 'UPDATE' -- 服务变更，按照询价单的价格更改 and ( enq_op_main_sub.SER_KEY0 != a.FRO_SER_KEY0 or enq_op_main_sub.SER_KEY1 != a.FRO_SER_KEY1 or enq_op_main_sub.SER_KEY2 != a.FRO_SER_KEY2 ) then isnull(a.enq_jny_price_sup, a.enq_jny_price) else enq_op_main_sub.enq_jny_price end , enq_op_main_sub.SER_KEY0 = a.FRO_SER_KEY0 , enq_op_main_sub.SER_KEY1 = a.FRO_SER_KEY1 , enq_op_main_sub.SER_KEY2 = a.FRO_SER_KEY2 , enq_op_main_sub.FRO_ENQ_JNY_DATE = a.FRO_ENQ_JNY_DATE from ( select a.*, b.enq_jny_price, b.enq_jny_price_sup from v_GRP_SER_SP a left join V_ENQ_OP_MAIN_SUB b on a.FRO_SER_ID = b.SER_ID and a.FRO_SER_CITY_ID = b.SER_CITY_ID and a.FRO_ENQ_JNY_DAY = b.ENQ_JNY_DAY and a.FRO_ENQ_JNY_SER_SUB_INDEX = b.ENQ_OP_SUB_ID_INDEX and a.GRP_ID = b.GRP_ID and b.ENQ_SELECT_STATE = 'CHECKED_TRUE' ) a where a.fro_enq_op_sub_id = enq_op_main_sub.enq_op_sub_id and (a.sup_down_id = @g_sup_id or a.sup_id = @g_sup_id) and a.gssm_id = @gssm_id ;
update GRP_SER_SP set fro_enq_op_id = a.enq_op_sub_id from ENQ_OP_MAIN_SUB a where a.ENQ_OTHER_SER_ID = GRP_SER_SP.GRP_SER_SP_ID and a.SUB_UNID = @sys_unid and a.enq_op_id = @enq_op_id and GRP_SER_SP.fro_enq_op_id = -1 ;
update GRP_SER_SP set GRP_SER_SP_CONFIRMED = 'Y' where gssm_id = @gssm_id ;
exec PR_AUTO_FIN_TYPE @ENQ_OP_ID,@G_SUP_ID,@G_ADM_ID ;

