select top 1 d.ADM_ID OP_ID,DEP_ID,PROFIT,GRP_VIS_MATERIAL,a.GRP_VISA ,GRP_TYPE ,GRP_VIS_DEF,GRP_AIR_DEF,GRP_CAMP_DEF ,ENQ_CAR_ID ,enq_remark ,D_C_REMARK ,D_NC_REMARK from GRP_MAIN a inner join GRP_GYAP_DOC b on a.grp_id=b.grp_id inner join ENQ_MAIN c on a.grp_id=c.grp_id left join ADM_USER d on a.OP_ID=d.ADM_ID and d.ADM_USR_STA_TAG='OK' and d.ADM_OP='COM_YES' where GRP_GYAP_ID=@GRP_GYAP_ID AND (ENQ_DEFAULT='COM_YES' OR ENQ_SELECT_STATE='CHECKED_TRUE') ORDER BY ENQ_SELECT_STATE desc ;
INSERT INTO GRP_MAIN ( ADM_ID, GRP_NAME, GRP_NIGHT, GRP_CODE, GRP_STA, SUP_ID, GRP_REMARK , GRP_cDATE, GRP_SDATE, GRP_TYPE, GRP_HY_CODE , GRP_RUN_MODEL ,SUP_DOWN_ID, GRP_PICK, GRP_UNID , GRP_COIN , OP_ID, DEP_ID ,GRP_VIS_MATERIAL, GRP_VISA , GRP_VIS_DEF,GRP_AIR_DEF,GRP_CAMP_DEF ) select ADM_ID, @GRP_NAME, @S_DAYS,'' ,'SCM_GRP_STA_NEW', @G_SUP_ID, @S_OTHERS , @sys_DATE, @S_FDATE, isnull(@GRP_TYPE,'GRP_YX'), 'Auto' , case when b.SUP_ID=@G_SUP_ID then 'GRP_RUN_COMBINE' else 'GRP_RUN_SINGLE' end, SUP_DOWN_ID, @PICK_UP, @UID , isnull(b.SUP_COIN_ID,1) , @OP_ID, @DEP_ID, @GRP_VIS_MATERIAL, @GRP_VISA , @GRP_VIS_DEF, @GRP_AIR_DEF, @GRP_CAMP_DEF from CRM_CONN a inner join sup_main b on a.sup_down_id=b.sup_id where a.crm_com_id=@crm_com_id and a.sup_up_id=@G_SUP_ID;
SELECT GRP_ID,SUP_DOWN_ID FROM GRP_MAIN WHERE GRP_UNID = @UID;
--生成团号 EXEC PR_GRP_GEN_CODE @G_SUP_ID, @GRP_ID;
insert into grp_coin (GRP_ID,COIN_FROM,COIN_TO,GRP_POINT)select @GRP_ID,COIN_FROM,COIN_TO,coin_point from sys_coin_point;
SELECT DEFAULT_VALUE as enq_remark from SYS_DEFAULT where tag='enq_remark' and sup_id=@g_sup_id and @enq_remark is null; SELECT DEFAULT_VALUE as D_C_REMARK from SYS_DEFAULT where tag='D_C_REMARK' and sup_id=@g_sup_id and @D_C_REMARK is null; SELECT DEFAULT_VALUE as D_NC_REMARK from SYS_DEFAULT where tag='D_NC_REMARK' and sup_id=@g_sup_id and @D_NC_REMARK is null;
INSERT INTO ENQ_MAIN ( SUP_ID, ADM_ID, ENQ_NO, GRP_ID, HEAD_NUM, DAY_NUM, PEOPLE_NUM , CHILD_NUM, CHILD_NO_NUM, BABY_NUM, SIG_NUM, DUB_NUM, THR_NUM, FOR_NUM, SUIT_NUM , F_CITY, F_DATE , ENQ_CREATE_TIME, ENQ_CAR_ID, ENQ_HOTEL_ID, sup_down_id , D_C_REMARK, D_NC_REMARK, ENQ_GAIN, CAR, GUIDE, HOTLE, MEAL , SENIC, FEE, PICK_UP, ENQ_UNID, CITYS , ENQ_DEFAULT , enq_remark,PROFIT ) select @g_SUP_ID, ADM_ID, '', GRP_ID, @HEAD_NUM, @S_DAYS, @S_PEOPLE , 0, 0, 0, 0, CEILING((@S_PEOPLE+@HEAD_NUM)/2.0), 0, 0, 0 , @S_FROM, @S_FDATE , getdate() , @ENQ_CAR_ID, @ENQ_HOTEL_ID, sup_down_id , @D_C_REMARK, @D_NC_REMARK, @ENQ_GAIN, @CAR, @GUIDE, @HOTLE, @MEAL , @S_SENS, @FEE, @PICK_UP, @UID, @S_CITYS , 'COM_YES' , @enq_remark,@PROFIT FROM GRP_MAIN WHERE GRP_UNID = @UID;
SELECT ENQ_ID TO_ENQ_ID FROM ENQ_MAIN WHERE ENQ_UNID=@UID;
EXEC PR_ADD_ENQ @TO_ENQ_ID, @g_sup_id, @g_adm_id;
UPDATE CURRENCY_FILE SET REF_ID=@TO_ENQ_ID,UNID=NEWID(),GRP_ID=@GRP_ID,ADM_ID=@g_adm_id ,RELATE_SUP_ID=@SUP_DOWN_ID WHERE UNID=@UID ;
select OPP_FROM_SUP_ID FROM CRM_OPPORTUNITY where OPP_ID=@OPP_ID ;
INSERT INTO CURRENCY_FILE (REF_ID,REF_TYPE,SUP_ID,FILE_TYPE, CURRENCY_REMARK , PIC_PHY_PATH , PIC_MD5 ,UNID, CURRENCY_EXT,CURRENCY_OB1,CURRENCY_OB2 ,GRP_ID,ADM_ID,RELATE_SUP_ID) select @TO_ENQ_ID,'ENQ',@G_SUP_ID,'REQUIRE','来自在线咨询,ID:'+convert(varchar(20),FILE_RID) ,case when substring(FILE_PATH,1,3)='/ic' then substring(FILE_PATH,4,999999) else FILE_PATH end FILE_PATH , FILE_MD5 ,NEWID(),FILE_EXT ,FILE_NAME,FILE_SIZE ,@GRP_ID,@g_adm_id,@OPP_FROM_SUP_ID from sys_atts where FILE_FROM ='CRM_OPPORTUNITY' and FILE_RID = @OPP_ID and FILE_STATUS='COM_YES' ;
--单团生成时，需要插入一条空合同 IF NOT EXISTS(SELECT * FROM CURRENCY_FILE WHERE [STATE]='USED' AND REF_TYPE = 'GRP_MAIN' AND REF_ID = @GRP_ID AND SUP_ID = @G_SUP_ID) INSERT INTO CURRENCY_FILE (REF_ID,REF_TYPE,SUP_ID,FILE_TYPE, CURRENCY_REMARK ,CURRENCY_SYNC_UNID,ADM_ID,RELATE_SUP_ID,GRP_ID) SELECT @GRP_ID,'GRP_MAIN',@G_SUP_ID,'PACT1','单团自动生成合同文件' ,@SYS_UNID,@G_ADM_ID,SUP_DOWN_ID,@GRP_ID FROM GRP_MAIN WHERE GRP_ID=@GRP_ID AND GRP_RUN_MODEL='GRP_RUN_SINGLE';
EXEC PR_SHARE_GRP_MAIN @GRP_ID;
--通知OP insert into LOG_MAIN(LOG_SRC,LOG_SRC_ID0,LOG_TYPE,LOG_MEMO ,LOG_PARA1,LOG_PARA0,LOG_TIME,SUP_ID,ADM_ID ,LOG_TO_ADM_ID) select 'GRP_MAIN',GRP_ID,'LOG_NEW_GRP','【新询价】'+grp_hy_code+'/'+grp_name ,'?mode=GRP_MAIN&GRP_ID='+convert(varchar(10),grp_id),'',getdate() ,@G_SUP_ID ,@G_ADM_ID ,OP_ID from grp_main where grp_id=@grp_id AND OP_ID!=@G_ADM_ID

INSERT INTO GRP_GYAP_DOC ( GRP_ID, GRP_GYAP_COURSE, GRP_GYAP_AGE, GRP_GYAP_TRAFFIC, GRP_GYAP_STAY, GRP_GYAP_TEACH, GRP_GYAP_INTRODUCE , GRP_GYAP_FEATURE, GRP_GYAP_ORGANIZATION, TITLE_IMG, BASE_IMG, INTRODUCE_IMG, FEATURE_IMG, ORGANIZATION_IMG , END_IMG, GRP_GYAP_STATE, SUP_ID, ADM_ID, CREATE_DATE, GRP_GYAP_NAME, GRP_GYAP_DAYS, GRP_GYAP_HEALTH_VACCINE , GRP_GYAP_ENGLISH_REQUIRE, GRP_GYAP_PARENT_COMPANY, GRP_GYAP_PARTNER, GRP_GYAP_PRICE, GRP_GYAP_PRICE_SINGLE , GRP_GYAP_CITY_INFO, GRP_GYAP_CAMP_INFO, GRP_GYAP_MDATE, GRP_GYAP_QRCODE_IMG, GRP_GYAP_PRICE_INCLUDE , GRP_GYAP_PRICE_EXCLUDE, GRP_GYAP_UNID, GRP_GYAP_REF_GRP_ID , GRP_GYAP_TYPE, GRP_GYAP_TIME, GRP_GYAP_ORGANIZER, GRP_GYAP_CONTRACTOR, GRP_GYAP_CONFERENCE_HALL , GRP_GYAP_SUPPORT_UNIT, GRP_GYAP_MEDIA_SUPPORT, GRP_GYAP_PARTICIPANTS, GRP_GYAP_MAIN_ACTIONS , GRP_GYAP_KEYNOTE_GUEST, GRP_GYAP_GUEST, GRP_GYAP_PRICE_TRAVEL,GRP_GYAP_AIM ,GRP_GYAP_DELEGATE ,GRP_GYAP_LAYOUT ,GRP_GYAP_SLOGAN,GRP_GYAP_PLACE,GRP_GYAP_PLAYER_FEE ,GRP_GYAP_PARENT_FEE,GRP_GYAP_ACT,GRP_GYAP_AGENT_PRICE ,GRP_GYAP_LOGO,GRP_GYAP_PUB_COUNTRY,GRP_GYAP_GROUP ) SELECT @GRP_ID, GRP_GYAP_COURSE, GRP_GYAP_AGE, GRP_GYAP_TRAFFIC, GRP_GYAP_STAY, GRP_GYAP_TEACH, GRP_GYAP_INTRODUCE , GRP_GYAP_FEATURE, GRP_GYAP_ORGANIZATION, TITLE_IMG, BASE_IMG, INTRODUCE_IMG, FEATURE_IMG, ORGANIZATION_IMG , END_IMG, GRP_GYAP_STATE, @G_SUP_ID, @G_ADM_ID, @SYS_DATE, @GRP_NAME, GRP_GYAP_DAYS, GRP_GYAP_HEALTH_VACCINE , GRP_GYAP_ENGLISH_REQUIRE, GRP_GYAP_PARENT_COMPANY, GRP_GYAP_PARTNER, GRP_GYAP_PRICE, GRP_GYAP_PRICE_SINGLE , GRP_GYAP_CITY_INFO, GRP_GYAP_CAMP_INFO, GRP_GYAP_MDATE, GRP_GYAP_QRCODE_IMG, GRP_GYAP_PRICE_INCLUDE , GRP_GYAP_PRICE_EXCLUDE, @sys_unid, GRP_ID , GRP_GYAP_TYPE, GRP_GYAP_TIME, GRP_GYAP_ORGANIZER, GRP_GYAP_CONTRACTOR, GRP_GYAP_CONFERENCE_HALL , GRP_GYAP_SUPPORT_UNIT, GRP_GYAP_MEDIA_SUPPORT, GRP_GYAP_PARTICIPANTS, GRP_GYAP_MAIN_ACTIONS , GRP_GYAP_KEYNOTE_GUEST, GRP_GYAP_GUEST, GRP_GYAP_PRICE_TRAVEL,GRP_GYAP_AIM ,GRP_GYAP_DELEGATE ,GRP_GYAP_LAYOUT ,GRP_GYAP_SLOGAN,GRP_GYAP_PLACE,GRP_GYAP_PLAYER_FEE ,GRP_GYAP_PARENT_FEE,GRP_GYAP_ACT,GRP_GYAP_AGENT_PRICE ,GRP_GYAP_LOGO,GRP_GYAP_PUB_COUNTRY,GRP_GYAP_GROUP FROM GRP_GYAP_DOC WHERE GRP_GYAP_ID=@GRP_GYAP_ID AND SUP_ID = @G_SUP_ID -- AUTO NEW_GRP_GYAP_ID ;
select GRP_GYAP_UNID FROM GRP_GYAP_DOC WHERE GRP_GYAP_ID=@GRP_GYAP_ID AND SUP_ID = @G_SUP_ID ;
UPDATE ENQ_MAIN SET D_C_REMARK=EXT_PRICE_INCLUDE from V_GRP_GYAP_DOC_EXT x WHERE x.EXT_KEY=@GRP_GYAP_UNID and ENQ_MAIN.GRP_ID=@GRP_ID AND ENQ_MAIN.SUP_ID = @G_SUP_ID AND EXT_PRICE_INCLUDE is not null and EXT_PRICE_INCLUDE!='' ;
UPDATE ENQ_MAIN SET D_NC_REMARK=EXT_PRICE_EXCLUDE from V_GRP_GYAP_DOC_EXT x WHERE x.EXT_KEY=@GRP_GYAP_UNID and ENQ_MAIN.GRP_ID=@GRP_ID AND ENQ_MAIN.SUP_ID = @G_SUP_ID AND EXT_PRICE_EXCLUDE is not null and EXT_PRICE_EXCLUDE!='' ;
-- 复制扩展字段 EXEC PR_EWA_HOR_COPY 'd27f38f9-4e73-4c91-8f96-a2281bf2c4da', @GRP_GYAP_UNID, @sys_unid , @G_SUP_ID, @G_ADM_ID;
-- 复制自定义字段 INSERT INTO GRP_GYAP_DOC_COM_FIELD (GRP_GYAP_ID,CF_ORD, CF_NAME, CF_CONTENT, CF_CDATE, ADM_ID, SUP_ID) SELECT @NEW_GRP_GYAP_ID,CF_ORD, CF_NAME, CF_CONTENT, @SYS_DATE, @G_ADM_ID, @G_SUP_ID from GRP_GYAP_DOC_COM_FIELD where GRP_GYAP_ID=@GRP_GYAP_ID ;
-- 创建推广资料 INSERT INTO GRP_GYAP_DOC_AD(GRP_GYAP_ID, OAF_ID, AD_ORD, SUP_ID, ADM_ID, AD_CDATE) SELECT @NEW_GRP_GYAP_ID, OAF_ID, AD_ORD, SUP_ID, @G_ADM_ID, @SYS_DATE FROM GRP_GYAP_DOC_AD WHERE GRP_GYAP_ID=@GRP_GYAP_ID ;
UPDATE PIC_MAIN SET PIC_STATUS='WEB_NWS_DEL' , ADM_ID = @G_ADM_ID , PIC_PARA4 = @EWA.DATE.STR1 WHERE REF_TAG = 'ENQ_JNY' AND REF_ID in ( select ENQ_JNY_ID from ENQ_JNY where enq_id = @ENQ_ID) AND SUP_ID = @G_SUP_ID AND (@IMP_JNY IS NULL OR @IMP_JNY='') -- 不导入行程时更新图片 ; -- 创建关联图片 INSERT into PIC_MAIN ( ref_id, REF_TAG, PIC_NAME, PIC_TYPE, PIC_PATH, PIC_REAL_PATH , PIC_MD5, PIC_UNID, PIC_CDATE,PIC_LENGTH, PIC_ORD,ADM_ID, PIC_STATUS, SUP_ID ) select c.id, REF_TAG, PIC_NAME, PIC_TYPE, PIC_PATH, PIC_REAL_PATH , PIC_MD5, PIC_UNID, PIC_CDATE,PIC_LENGTH, PIC_ORD, b.ADM_ID, PIC_STATUS, b.SUP_ID from ENQ_JNY a inner join PIC_MAIN b on a.ENQ_JNY_ID = b.REF_ID and REF_TAG='ENQ_JNY' inner join ( select ENQ_JNY_ID as id , ENQ_JNY_DAY as inc from ENQ_JNY where enq_id = @ENQ_ID ) c on a.ENQ_JNY_DAY = c.inc where a.ENQ_ID IN ( SELECT enq_id FROM ENQ_MAIN A INNER JOIN GRP_GYAP_DOC B ON A.GRP_ID = B.GRP_ID AND B.GRP_GYAP_ID = @GRP_GYAP_ID ) AND (@IMP_JNY IS NULL OR @IMP_JNY='') -- 不导入行程时更新图片 ;
-- app设置 INSERT INTO GRP_GYAP_DOC_APP_SETTING( GRP_GYAP_ID, SET_TAG, SET_SHOW, SET_TITLE, SET_TITLE_EN, SUP_ID, ADM_ID , SET_CDATE, SET_ORD, SET_GRP ) select @NEW_GRP_GYAP_ID, SET_TAG, SET_SHOW, SET_TITLE, SET_TITLE_EN, @G_SUP_ID, @G_ADM_ID , @SYS_DATE, SET_ORD, SET_GRP from GRP_GYAP_DOC_APP_SETTING where GRP_GYAP_ID=@GRP_GYAP_ID ;
INSERT INTO WEB_QA_MAIN (QA_TYPE, QA_QUESTION, QA_EMAIL, QA_CDATE, QA_USR_ID, QA_STATUS, QA_ANSWER, QA_ADATE, QA_ADM_ID, QA_A_MDATE, QA_READ, QA_READ_DATE, QA_MADM_ID, REF_ID, REF_TAG, QA_IP, QA_NAV_AGENT, SIT_ID, QA_PID, QA_PUBLISH, REF_NAME, QA_FROM_URL, QA_ORD, QA_COUNTRY_ID, a.SUP_ID) SELECT QA_TYPE, QA_QUESTION, QA_EMAIL, QA_CDATE, QA_USR_ID, QA_STATUS, QA_ANSWER, QA_ADATE,QA_ADM_ID QA_ADM_ID, QA_A_MDATE, QA_READ, QA_READ_DATE, QA_MADM_ID, newGgd.GRP_GYAP_UNID , REF_TAG, QA_IP, QA_NAV_AGENT, SIT_ID, QA_PID, QA_PUBLISH, REF_NAME, QA_FROM_URL, QA_ORD, QA_COUNTRY_ID, A.SUP_ID FROM WEB_QA_MAIN a inner join GRP_GYAP_DOC ggd on a.REF_ID = ggd.GRP_GYAP_UNID inner join GRP_GYAP_DOC newGgd on ggd.GRP_ID = newGgd.GRP_GYAP_REF_GRP_ID WHERE a.REF_TAG in ('GRP_GYAP_DOC_COS','GRP_GYAP_DOC') and newGgd.GRP_GYAP_ID = @NEW_GRP_GYAP_ID and ggd.GRP_GYAP_ID=@GRP_GYAP_ID AND a.sup_id = @G_SUP_ID

EXEC PR_ENQ_JNY_IMPORT @TO_ENQ_ID , @SYS_UNID ,@FROM_ENQ_ID , @G_SUP_ID , @G_ADM_ID ;
update ENQ_PRICE set SIG_R_PRICE=s.s_SIG_R_PRICE from (select SIG_R_PRICE s_SIG_R_PRICE,ENQ_ENTRY s_ENQ_ENTRY from ENQ_PRICE WHERE enq_id=@FROM_ENQ_ID) s where ENQ_ID = @TO_ENQ_ID and ENQ_ENTRY=s_ENQ_ENTRY ;
exec PR_ENQ_PRICE_FIN @TO_ENQ_ID

