(function() {
    let ewa = EWA.F.FOS["@sys_frame_unid"];

    function getObj(exp) {
        return $('#EWA_LF_@sys_frame_unid').find(exp);
    }

    function load_air_citys() {
        var ids = [];
        var eles = [];
        getObj('.ewa-lf-data-row ').each(function() {
            var ser = $(this).find('#SER_ID');
            if (ser.attr("title") == '1') { //机票
                var eleDes = $(this).find('#SER_DES');
                var des = eleDes.text().split(' ')[0];
                var citys = des.split('_');
                ids.push(citys[0]);
                ids.push(citys[1]);
                eleDes.attr("f_city", citys[0]);
                eleDes.attr("t_city", citys[1]);
                eles.push(eleDes);
            }
        });

        if (ids.length == 0) {
            return;
        }

        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "ExtendAction0");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("ids_split", ids.join(","));
        var u = u1.GetUrl();
        $J(u, function(rst) {
            var map = $J2MAP(rst, 'CITY_ID');
            for (var n in eles) {
                var d = eles[n];

                var f_name = map[d.attr('f_city')].CITY_NAME;
                var t_name = map[d.attr('t_city')].CITY_NAME;

                d.text(f_name + "-" + t_name);

            }
        });
    }

    ewa.ext_addToPurchase = function() {
        let ids = ewa.SelectChecked();
        console.log("ids:", ids);
        let u = ewa.getUrlClass();
        let parasArray = [];
        parasArray[0] = {
            Name: "ids",
            Value: ids
        };
        ewa.DoAction(this, "add_to_purchase", "", "", parasArray, "");
    };
    ewa.CheckedAllAfter = function(obj) {
        getObj('.ewa-col-ENQ_JNY_SER_SUB_ID input[type=checkbox]').each(function() {
            checkedStatus(this);
        });
    };

    function checkedStatus(checkbox) {
        let that = checkbox;
        setTimeout(function() {
            if (that.checked) {
                $(that).parent().parent().removeClass('unchecked');
                unChecked[that.value] = false;
            } else {
                $(that).parent().parent().addClass('unchecked');
                unChecked[that.value] = true;
            }
        }, 10);
    }
    let unChecked = {};
    if ("@p_frame_unid" && EWA.F.FOS["@p_frame_unid"]) {
        if (!EWA.F.FOS["@p_frame_unid"].unChecked) {
            EWA.F.FOS["@p_frame_unid"].unChecked = {};
        }
        unChecked = EWA.F.FOS["@p_frame_unid"].unChecked;
    }
    ewa.ReloadAfter = function(httpReferer) {
        load_air_citys();
        ewa.CheckedAllAfter();

        $('.ewa-col-ENQ_JNY_SER_SUB_ID input[type=checkbox]').on('change', function() {
            checkedStatus(this);
        });

        getObj('.ewa-col-ENQ_JNY_SER_SUB_ID input[type=checkbox]').each(function() {
            let id = this.value;
            if (unChecked[id]) {
                $(this).prop('checked', false);
            } else {
                $(this).prop('checked', true);
            }
            checkedStatus(this);
        });
        ewa._IsCheckedAll = false;
    };
    // 初始化执行一次
    ewa.ReloadAfter();
})()

