(function() {
    let ewa = EWA.F.FOS["@sys_frame_unid"];

    ewa.ext_do_deletes=function(){
        let ids = EWA.F.FOS['@SYS_FRAME_UNID'].SelectChecked();
        if(ids == ''){
            $Tip('请选择要删除的服务', 2221);
            return;
        }
        let u = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);

        let enqOpMainState='@ENQ_OP_MAIN_STATE'; //供应商确认状态

        if(enqOpMainState=="ENQ_NEW"){
            let paras={}
            ewa.DoAction(null,"OnFrameDelete","确定要删除选定的服务吗？","",paras);
        }else{
            u.RemoveEwa(); 
            u.AddParameter("deletes_split", ids);
            u.AddParameter("ewa_mtype", "N");
            let paras = u.GetParas();
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '/business/enq/enq.xml', 'GRP_SER_SP_MAIN.F.NM', false, paras);
        }
    }

    ewa.ext_add_sers=function(){
        let u = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u.RemoveEwa(); 
        u.AddParameter("ewa_in_dialog",1);
        let paras = u.GetParas();
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
            '/business/enq/enq.xml', 'ENQ_JNY_SER_SUB.Lf.V', false, paras);
    }

    function load_air_citys() {
        var ids = [];
        var eles = [];
        $('#EWA_LF_@sys_frame_unid .ewa-lf-data-row ').each(function() {
            var eleDes = $(this).find('#SER_DES');
            if (eleDes.attr("ser_tag") == 'SER_TAG_AIR') { //机票
                var des = eleDes.text().split(' ')[0];
                var citys = des.split('_');
                ids.push(citys[0]);
                ids.push(citys[1]);
                eleDes.attr("f_city", citys[0]);
                eleDes.attr("t_city", citys[1]);
                eles.push(eleDes);
            }

        });
        if (ids.length == 0) {
            return;
        }
        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "ExtendAction1");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("ids_split", ids.join(","));
        var u = u1.GetUrl();
        $J(u, function(rst) {
            var map = $J2MAP(rst, 'CITY_ID');
            for (var n in eles) {
                var d = eles[n];
                var f_name = map[d.attr('f_city')].CITY_NAME;
                var t_name = map[d.attr('t_city')].CITY_NAME;
                d.text(f_name + "-" + t_name);
            }
        });
    }
    function showDiff1(td0, td1, isNumber) {
        let old_val = $(td0).text();
        let new_val = $(td1).text();
        if (old_val == new_val) {
            return;
        }
        $(td0).css('background', 'pink').css('font-weight', 'bold').css('color', '#000');
        $(td1).css('background', 'pink').css('font-weight', 'bold').css('color', '#000');

        if (!isNumber) {
            return;
        }
        // let diff = new_val * 1 - old_val * 1;
        // let s = diff > 0 ? "+" + diff : diff;
        // let color = diff > 0 ? 'lightgreen' : "pink"
        // $(td).append("<span > (" + s + ")</span>").css('background', color).css('font-weight', 'bold');
    }
    function showDiff(td, isNumber) {
        let old_val = $(td).find('span:eq(0)').text()
        let new_val = $(td).find('span').last().text();

        if (new_val== "" || old_val == new_val) {
            $(td).find('span,br').last().hide();
            return;
        }
        $(td).css('background', 'pink').css('font-weight', 'bold').css('color', '#000');
        $(td).find('span:eq(0)').addClass('enq');
        (td).find('span').last().addClass('purchase');
        if (!isNumber) {
            return;
        }
        // let diff = new_val * 1 - old_val * 1;
        // let s = diff > 0 ? "+" + diff : diff;
        // let color = diff > 0 ? 'lightgreen' : "pink"
        // $(td).append("<span > (" + s + ")</span>").css('background', color).css('font-weight', 'bold');
    }
    ewa.ReloadAfter = function(httpReferer) {
        load_air_citys();
        if ("@only_changes" == "") {
            let that = this;
            // that.mergeHeaders('CUR_ENQ_ID', '生效询价单', 7);
            // that.mergeHeaders('ORDER_ENQ_ID', '采购单', 7);
            // that.mergeHeaders('CHANGE_NUM', '变更单', 4);
        }
        $('#EWA_LF_@sys_frame_unid .ewa-lf-data-row').each(function() {
            // let td0 = $(this).find('.ewa-col-SER_SUB_DES')
            // let td1 = $(this).find('.ewa-col-ORDER_DES')
            // showDiff(td0, td1);
            // let td2 = $(this).find('.ewa-col-SUB_NUM');
            // let td3 = $(this).find('.ewa-col-SUB_NUM_SUP');
            // showDiff(td2, td3);
            // let td4 = $(this).find('.ewa-col-ser_sub_date');
            // let td5 = $(this).find('.ewa-col-order_date');
            // showDiff(td4, td5);

            ewa.Merge('ORDER_DES', 'SER_SUB_DES', '<br>', function(td){
                showDiff(td)
            });
            ewa.Merge('SUB_NUM_SUP', 'SUB_NUM', '<br>', function(td){
                showDiff(td)
            });
            ewa.Merge('order_date', 'ser_sub_date', '<br>', function(td){
                showDiff(td)
            });
            ewa.Merge('ORDER_ENQ_ID', 'CUR_ENQ_ID', '<br>', function(td){
                showDiff(td)
            });
            // ewa.Merge('ENQ_JNY_PRICE_SUP', 'ENQ_JNY_PRICE', '<br>', function(td){
            //     showDiff(td)
            // });
            $(this).find('span[id=COST_CHANGE], span[id=num_diff]').each(function() {
                var cost_change = $(this).text().replace(/,/ig, '');
                var diff = cost_change * 1;
                if (diff > 0) {
                    $(this).addClass('plus');
                } else if (diff < 0) {
                    $(this).addClass('reduce');
                } else {
                    $(this).hide();
                }
            });
        });

    };
    // 初始化执行一次
    EWA.F.FOS["@sys_frame_unid"].ReloadAfter();
})();

