Set.Sql:
SELECT DISTINCT ser_id FROM enq_jny_ser_sub WHERE fro_enq_id = @enq_id AND sup_id = @g_sup_id AND sup_down_id = @SUPPLY -- ewa_join ser_ids, ser_id ;
SELECT DISTINCT enq_jny_id FROM enq_jny_ser_sub WHERE fro_enq_id = @enq_id AND sup_id = @g_sup_id AND sup_down_id = @SUPPLY -- ewa_join enq_jny_ids, enq_jny_id ;
SELECT CASE WHEN @SUPPLY IS NOT NULL THEN 'COM_YES' ELSE 'COM_NO' END AS ENQ_OP_IS_COOP

SELECT '团已经关闭,不能进行操作' AS EWA_ERR_OUT from grp_main where grp_id=@grp_id and CLAC_STATUS IN('FINALLY_CLOSE','CLOSE') ; /* select '下单的货币不一致' AS EWA_ERR_OUT WHERE exists( select count(*) FROM ( select distinct coin_id FROM ENQ_JNY_SER_SUB A WHERE a.ser_id IN ( SELECT col FROM dbo.f_split(@ser_ids,',') ) and a.ENQ_JNY_ID IN ( SELECT col FROM dbo.f_split(@enq_jny_id,',') ) ) aa having count(*)>1 ) */
SELECT '当前没有成交的询价单，请审批后再下单' AS EWA_ERR_OUT WHERE NOT EXISTS ( SELECT * FROM ENQ_MAIN em WHERE GRP_ID = @GRP_ID AND ENQ_SELECT_STATE = 'CHECKED_TRUE' );
SELECT '当前询价单和成交的询价单不一致' AS EWA_ERR_OUT FROM enq_main WHERE enq_id = @enq_id AND enq_id NOT IN ( SELECT enq_id FROM ENQ_MAIN em WHERE GRP_ID = @GRP_ID AND ENQ_SELECT_STATE = 'CHECKED_TRUE' );
/* start 自动创建客户、供应商、联系人和管理员 */ -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' SELECT '新供应商《'+@new_sup_name+'》已经存在, 请选用已合作供应商' AS EWA_ERR_OUT from crm_com a WHERE crm_com_name = @new_sup_name and SUP_ID = @G_SUP_ID ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' INSERT into crm_com (CRM_COM_NAME, CRM_COM_CDATE, ADM_ID, USE_STATE, CRM_COM_COOP_STATUS, SUP_ID , CRM_COM_STATE, CRM_COM_SALE, CRM_COM_NOTE ) VALUES(@new_sup_name, @SYS_DATE, @G_ADM_ID, 'USED', 'COOP_STATUS_NEW', @G_SUP_ID , 'CRM_S_OK', 'CRM_SALE_NEW', '询价单创建待定客户' ) -- auto new_crm_com_id ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' insert into crm_cus (CRM_COM_ID, SUP_ID, CRM_CUS_NAME, CRM_CUS_CDATE, CRM_CUS_MASTER, ADM_ID, CRM_CUS_STATUS) VALUES (@new_crm_com_id, @G_SUP_ID, @new_sup_name.140, @SYS_DATE, 'COM_YES', @G_ADM_ID, 'CRM_CUS_NEW') -- auto new_crm_cus_id ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' exec PR_SUP_MAIN_FROM_CRM_COM @new_crm_com_id, @G_SUP_ID, @G_ADM_ID, 'SUP_TYPE_SUPPLY' ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' -- PR_ADM_FROM_CRM_CUS( CRM_CUS_ID int, ADM_DEP_ID int, SET_ADM_PWD, adm_id int output) exec PR_ADM_FROM_CRM_CUS @NEW_CRM_CUS_ID, null, null, @new_adm_id_output ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' select SUP_DOWN_ID as NEW_SUP_ID from crm_conn a WHERE SUP_UP_ID = @G_SUP_ID and crm_com_id = @new_crm_com_id ; -- ewa_test /* end 自动创建客户、供应商、联系人和管理员 */
INSERT INTO ENQ_OP_MAIN ( ENQ_ID , SUP_ID , ENQ_JNY_ID, OWN_SUP_ID, CREATE_TIME, ADM_ID, SER_IDS , HTML,REMARK,STATE,PACT_HTML,POPLE_NUM,CAR,GUIDE,HOTLE,MEAL,SENIC,FEE , PICK_UP,ALL_PRICE,SHOPPING,PRACE,SPECIAL,SPECIAL_REMARK,SUP_TYPE , ENQ_METHOD,JNY_ADM_ID , ENQ_OP_CONTACT, ENQ_OP_CT_PHONE, ENQ_OP_CT_EMAIL,ENQ_OP_PAY_REMARK,ENQ_OP_SUP_ACC_ID,ENQ_OP_UNID , AUTO_JNY, FRO_GRP_ID ) VALUES ( @ENQ_ID , isnull(@NEW_SUP_ID, @SUP_ID) , @ENQ_JNY_IDS, @G_SUP_ID, @SYS_DATE, @G_ADM_ID, @SER_IDS , @HTML,@REMARK,'ENQ_NEW',@PACT_HTML,@POPLE_NUM,@CAR,@GUIDE,@HOTLE,@MEAL,@SENIC,@FEE , @PICK_UP,@ALL_PRICE,@SHOPPING,@PRACE,@SPECIAL,@SPECIAL_REMARK,@SUP_TYPE , @ENQ_METHOD,@JNY_ADM_ID -- 订单联系人 , @ENQ_OP_CONTACT, @ENQ_OP_CT_PHONE, @ENQ_OP_CT_EMAIL ,@ENQ_OP_PAY_REMARK,@ENQ_OP_SUP_ACC_ID,@SYS_UNID , @AUTO_JNY, @GRP_ID ) -- auto enq_op_id ;
INSERT INTO ENQ_OP_MAIN_SUB ( enq_op_id, ENQ_JNY_ID, SER_CONN_ID, SER_ID , SUP_ID, SUP_DOWN_ID , ENQ_JNY_PRICE, ENQ_JNY_PRICE_OP, ENQ_JNY_PRICE_SUP , COIN_ID, SUB_UNID, SUB_NUM, SUB_TAG , ENQ_OTHER_SER_ID, CP_TYPE , SER_CITY_ID, SER_KEY0, SER_KEY1, SER_KEY2, COIN_ID_SUP -- 20240727 新增 guolei , FRO_GRP_ID, FRO_ENQ_ID , FRO_ENQ_JNY_DAY -- 订单创建时，原始的第几天 , FRO_ENQ_JNY_DATE-- 订单创建时，原始的日期 , FROM_ENQ_JNY_SER_SUB_ID , ENQ_OP_SUB_ID_INDEX ) SELECT @enq_op_id, a.ENQ_JNY_ID, A.SER_CONN_ID, A.SER_ID , @g_sup_id, isnull(@NEW_SUP_ID, @SUP_ID) , ENQ_JNY_PRICE, ENQ_JNY_PRICE_OP, /*ENQ_JNY_PRICE*/ null , a.COIN_ID, SUB_UNID, SUB_NUM, SUB_TAG , ENQ_OTHER_SER_ID, CP_TYPE , B.CITY_ID, B.SER_KEY0, B.SER_KEY1, B.SER_KEY2, a.COIN_ID , @GRP_ID, @ENQ_ID , c.ENQ_JNY_DAY , c.ENQ_JNY_DATE , a.ENQ_JNY_SER_SUB_ID , a.ENQ_JNY_SER_SUB_INDEX FROM ENQ_JNY_SER_SUB A INNER JOIN SER_CONN B ON A.SER_CONN_ID = B.SER_CONN_ID INNER join enq_jny c on a.enq_jny_id = c.enq_jny_id AND c.ENQ_JNY_ID IN ( SELECT col FROM dbo.f_split(@enq_jny_ids,',') ) WHERE a.ser_id IN (SELECT col FROM dbo.f_split(@ser_ids,',') ) AND a.ENQ_JNY_SER_SUB_ID in (@SUB_IDS_SPLIT) AND ( a.SUP_ID = @g_sup_id or exists ( -- 采购单的执行者（例如：地接） select 1 from SHARE_DATA sd WHERE GRP_ID = @GRP_ID and sd_ref = 'ENQ_OP_MAIN.SUP_ID' and sd_data = @g_sup_id ) ) AND (SUB_TAG = 'AUTO' OR (SUB_TAG IS NULL AND ENQ_OTHER_SER_ID>0))

DELETE FROM GRP_FIN_TYPE WHERE GRP_ID = @GRP_ID AND FIN_TYPE = 0 AND RELATE_SUP_ID = @SUP_ID AND GRP_FIN_TYPE_FROM = 'ENQ_OP_MAIN' AND GRP_FIN_TYPE_REFID = @ENQ_OP_ID;
UPDATE ENQ_OP_MAIN_SUB SET enq_jny_price_sup = enq_jny_price WHERE enq_op_id = @enq_op_id ;
INSERT INTO GRP_FIN_TYPE ( GRP_ID, ENQ_ID, SUP_ID, FIN_TYPE_NAME, COS_PRICE, FIN_TYPE, FIN_TYPE_GROUP, RELATE_SUP_ID, TYPE_MEMO, COIN_ID, FLAGS, SALES_ID, GRP_FIN_TYPE_CDATE, GRP_FIN_TYPE_FROM, GRP_FIN_TYPE_REFID, UNID ) SELECT @GRP_ID, @ENQ_ID, @G_SUP_ID, '供应商支付计划', pp, 0, 'FINTYP_IN', @SUP_ID, '向供应商支付服务费：' + sup_name, coin_id, @FLAGS, @G_ADM_ID, GETDATE(), 'ENQ_OP_MAIN', @ENQ_OP_ID, NEWID() FROM ( SELECT -1 AS FF, 999999 AS SS, '总价' AS DD, @SUP_ID AS GG, cast(sum(isnull(isnull(enq_jny_price_sup, enq_jny_price) * sub_num, 0.0)) AS varchar) + '/' + COIN_KEY AS sup_name, a.coin_id, sum(isnull(isnull(enq_jny_price_sup, enq_jny_price) * sub_num, 0.0)) pp FROM ENQ_OP_MAIN_SUB a INNER JOIN sys_coin b ON a.coin_id = b.coin_id WHERE a.enq_jny_id IN ( SELECT col FROM dbo.f_split (@ENQ_JNY_ID, ',') ) AND a.sup_down_id = @SUP_ID AND a.enq_op_id = @enq_op_id GROUP BY a.coin_id, b.COIN_KEY ) AS TEMP -- auto GRP_FIN_TYPE_ID ; INSERT INTO GRP_PAY_APPLY ( APPLY_USER, APPLY_GRP_ID, APPLY_SUP_ID, APPLY_TITLE, APPLY_CONTENT, PAY_SUP_ID, ACCOUNT, APPLY_TIME, APPLY_STATUS, COIN_ID, GRP_ID, GRP_FIN_TYPE, PAY_TYPE, ADM_ID, UNID, COIN_POINT ) SELECT @G_ADM_ID, @GRP_ID, SUP_ID, FIN_TYPE_NAME, TYPE_MEMO, RELATE_SUP_ID, COS_PRICE, GETDATE(), 'VIS_FIN_NO', COIN_ID, @GRP_ID, @GRP_FIN_TYPE_ID, 'PAY_BANK', @G_ADM_ID, UNID, NULL FROM GRP_FIN_TYPE WHERE GRP_FIN_TYPE_ID = @GRP_FIN_TYPE_ID;

Set.Bottom:
EWA.F.FOS["@sys_frame_unid"].calc=function(){
    function mm(v1) {
        var v2 = v1 * 1;
        return v2.fm(2);
    }

    //刷新时先删除之前的合计行
    $('#EWA_LF_@sys_frame_unid>tbody>tr[ewa_key=-1]').remove();

    var tb = $X('EWA_LF_@sys_frame_unid');
    if (tb.rows.length == 1) {
        return;
    }
    var v1 = 0;
    var v1_1 = 0;
    var v2 = 0;
    var v2_2 = 0; //单价差单报价特殊处理
    var v3 = 0;
    var v3_3 = 0; //单价差利润特殊处理
    var v4 = 0;
    var v5 = 0;
    var v6 = 0;
    let t_sig_price=0;
    let t_sig_price_ss=0; //单价差

    var tr;
    for (var i = 1; i < tb.rows.length; i++) {
        var r = tb.rows[i];
        if (i == 1) {
            tr = tb.insertRow(-1);
            for (var m = 0; m < r.cells.length; m++) {
                var td = tr.insertCell(-1);
                td.className = "EWA_TD_M";
                td.style.color = 'blue';
                td.style.fontWeight = 'bold';
                if(m>0){
                    td.style.textAlign = 'right';
                }
                td.innerHTML = '&nbsp;';
            }
        }

        //v1 += GetInnerText(r.cells[2])*1;
        if (i == 3) //单价差单报价特殊处理
        {
            v2_2 += GetInnerText(r.cells[3]).replace(/,/g, '') * 1;
        } else {
            v2 += GetInnerText(r.cells[3]).replace(/,/g, '') * 1;
        }
        if (i == 3) //单价差利润特殊处理
        {
            v3_3 += GetInnerText(r.cells[4]).replace(/,/g, '') * 1;
        } else {
            v3 += GetInnerText(r.cells[4]).replace(/,/g, '') * 1;
        }
        if (i == 3) //单价差低价特殊处理
        {
            v1_1 += GetInnerText(r.cells[2]).replace(/,/g, '') * 1;
        } else {
            v1 += GetInnerText(r.cells[2]).replace(/,/g, '') * 1;
        }
        //v3 += GetInnerText(r.cells[4])*1;
        v4 += GetInnerText(r.cells[5]).replace(/,/g, '') * 1;
        v5 += GetInnerText(r.cells[6]).replace(/,/g, '') * 1;
        v6 += GetInnerText(r.cells[7]).replace(/,/g, '') * 1;

        if(i==3){
            t_sig_price_ss = GetInnerText(r.cells[1]).replace(/,/g, '') * 1;
        }else{
            t_sig_price += GetInnerText(r.cells[1]).replace(/,/g, '') * 1;
        }

    }
    tr.cells[0].innerHTML = '<span class=IX_SPAN>合计</span>';
    tr.cells[1].innerHTML = '<span class=IX_SPAN>' + mm(t_sig_price) + '/' + mm(t_sig_price + t_sig_price_ss) + '</span>';
    tr.cells[2].innerHTML = '<span class=IX_SPAN>' + mm(v1) + '/' + mm(v1 + v1_1) + '</span>';
    //tr.cells[3].innerHTML='<span class=IX_SPAN>'+mm(v2)+'/'+mm(v2+v2_2)+'</span>';	
    tr.cells[4].innerHTML = '<span class=IX_SPAN>' + mm(v3) + '/' + mm(v3 + v3_3) + '</span>';
    tr.cells[5].innerHTML = '<span class=IX_SPAN>' + mm(v4) + '</span>';
    tr.cells[6].innerHTML = '<span class=IX_SPAN>' + mm(v5) + '</span>';
    tr.cells[7].innerHTML = '<span class=IX_SPAN>' + mm(v6) + '</span>';
    if (v5 != 0) {
        tr.cells[8].innerHTML = '<span class=IX_SPAN>' + mm(v5 / v4 * 100 - 100) + '</span>';
    }
    //给合计行加入id方便刷新时删除
    $(tr).attr('ewa_key', '-1');
}

EWA.F.FOS["@sys_frame_unid"].ReloadAfter = function(httpReferer) {
   EWA.F.FOS["@sys_frame_unid"].calc();
   EWA.F.FOS["@sys_frame_unid"].ext_install_estimate();
};


