EWA.F.FOS["@SYS_FRAME_UNID"].ext_update_sp_check=function(GRP_SER_SP_ID, sta_in, sta_out, ssta, gftid) {
    let ggsmId="@GSSM_ID";
    if(!ggsmId){
        if (sta_in != 'FLOW_OP') {
            alert('流程已经开始，已经不能修改了！');
            return
        }

        if (gftid != null && gftid != "") {
            alert('已生成过支出计划,不能删除！');
            return
        }
    }
    let x = 'business/enq/grp_ser_sp.xml';
    let i = 'GRP_SER_SP.Frame.NewModify';
    var paras = 'EWA_MTYPE=M&GRP_SER_SP_ID=' + GRP_SER_SP_ID + '&SUP_DOWN_ID=@SUP_DOWN_ID&ENQ_OP_ID=@ENQ_OP_ID';
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', x, i, false, paras);
}

EWA.F.FOS["@SYS_FRAME_UNID"].ext_del_sp=function(GRP_SER_SP_ID, sta_in, sta_out, ssta, gftid) {
    console.log(GRP_SER_SP_ID);
    //if (sta_in != 'FLOW_OP') {
    //    alert('流程已经开始，已经不能删除了！');
    //    return
    //}

    if (gftid != null && gftid != "") {
        alert('已生成过支出计划,不能删除！');
        return
    }
    var paras = [];
    paras[0] = {
        Name: 'GRP_SER_SP_ID',
        Value: GRP_SER_SP_ID
    };
    paras[1] = {
        Name: 'ENQ_OP_ID',
        Value: '@ENQ_OP_ID'
    };
    var u = EWA.CP + '/EWA_STYLE/cgi-bin/?xmlname=@xmlname&itemname=@itemname';
    u += "&EWA_ACTION=OnFrameDelete&EWA_AJAX=JSON&GRP_SER_SP_ID=" + GRP_SER_SP_ID;
    u += "&ENQ_OP_ID=@ENQ_OP_ID";

    if (!window.confirm('您确认删除么!？')) {
        return;
    }

    console.log(u);
    $J2(u, function(rst) {
        if(rst.indexOf("EWA.UI.Msg.ShowError")>=0){
            eval(rst);
            return;
        }
        $Tip('删除成功', 2000);
        EWA.F.FOS["@sys_frame_unid"].Reload();
    });
}

EWA.F.FOS["@sys_frame_unid"].ext_grp_oth=function(grpOthId,grpId){
    if(!grpOthId){
        return;
    }
    let paras="EWA_MTYPE=M&gid="+grpId+"&GRP_OTH_ID="+grpOthId;
    EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid","/business/group/op.xml","GRP_OTH_COST.Frame.NewModify",false,paras);
}

EWA.F.FOS["@sys_frame_unid"].ReloadAfter = function() {
    let sum = 0;
    $('#EWA_LF_@sys_frame_unid .ewa-lf-data-row').each(function() {
