EWA.F.FOS["@SYS_FRAME_UNID"].DelayReloadGrp=function(idx){
    if(!idx){
        idx=1;
        $Tip("加载中...",5335);
    }
    console.log(idx);
    if(idx>100){
        alert("加载失败，请手动刷新");
        return;
    }
    let len=_EWA_DIALOGS.length;
    if(len>0 && _EWA_DIALOGS[len-1]){
        window.setTimeout(function() {
            EWA.F.FOS["@SYS_FRAME_UNID"].DelayReloadGrp(++idx);
        }, 186);
        return;
    }
    let u=new EWA_UrlClass();
    u.RemoveParameter("ENQ_ID");
    window.location.href=u.GetUrl();
}
