(function() {
    let ewa = EWA.F.FOS["@sys_frame_unid"];
    EWA.F.FOS["@sys_frame_unid"].AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        var cnt_td = newTr.cells[0]; //新行的td
        var div = $("<div style='width:" + $('body').width() + "px;oveflow:auto'></div>");

        $(cnt_td).append(div)
        var td = $(tr).find("#enq_id")
        var sna_id = td.attr("sna_id");
        var sna_enq_id = td.attr("sna_enq_id");

        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("xmlName", "business/enq/snapshot.xml");
        u1.AddParameter("ITEMNAME", "SANPSHOT");
        u1.AddParameter("sna_id", sna_id);
        u1.AddParameter("sna_enq_id", sna_enq_id);
        u1.AddParameter("enq_id",key);
        var ajax_url = u1.GetUrl();
        $Install(ajax_url, div, function() {
            console.log('install ok');
        });

    });

    EWA.F.FOS["@sys_frame_unid"].ext_signQrcode=async function(obj){
        let effectiveDays = 7;

        let tr=$(obj).closest("tr");
		let supUnid = tr.attr("data-agent-sup-unid");
		let supName = tr.attr("data-agent-sup-name");
		let supId = tr.attr("data-agent-sup-id");
        let grpUnid = tr.attr("data-grp-unid");
		let grpHyCode = tr.attr("data-grp-hy-code");
		let grpName = tr.attr("data-grp-name");
		let enqId = tr.attr("ewa_key");

        let u1 = ewa.getUrlClass();
        u1.RemoveEwa();
        u1.AddParameter("XMLNAME","/business/common/tools.xml");
        u1.AddParameter("ITEMNAME","QRCODE.F.N");
        u1.AddParameter("ewa_ajax","json");
        u1.AddParameter("ewa_action","getDaysOfFpUnid");
        u1.AddParameter("EFFECTIVE_DAYS",effectiveDays);
        u1.AddParameter("FP_REF_ID",enqId);
        u1.AddParameter("FP_VALIDCODE",supId);
        let fpLog=JSON.stringify({"ENQ_ID":enqId,"SUP_ID":supId});
        u1.AddParameter("fp_Log",fpLog);
        let validUnid=await new Promise((resolve) => {
            $J1(u1.GetUrl(),function(rst){
                return resolve(rst[0].FP_UNID);
            })
        });

        if(!validUnid){
            $Tip("获取fp_unid错误");
            return;
        }


        let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";

		let targetUrl = "https://" + domain + "/" + (EWA.CP.split("/")[1])
		    +"/customer/study-tour/agent-agreement.jsp?grp_unid=" + grpUnid
		    +"&enq_id="+enqId
		    +"&sup_unid="+supUnid
		    +"&mode=agreement"
		    +"&valid_unid="+validUnid;

		let tip = grpName + '<br>' + grpHyCode + '<br>' +supName+"<br>（有效期"+effectiveDays+"天）";
		let u3 = new EWA_UrlClass("/");
		u3.AddParameter("target_url", targetUrl);
		u3.AddParameter("convert_short_url", 1);
		u3.AddParameter("tip", tip);
		u3.AddParameter("img_name", grpHyCode);

		let paras = u3.GetParas();
		EWA.UI.Dialog.OpenFrame("create_qrcode", "/business/common/tools.xml", "QRCODE.F.N", false, paras);
    }

    if ("@flow_hidden") { //流程默认选择第一个
        EWA.F.FOS["@sys_frame_unid"].ReloadAfter = function(httpReferer) {
            $('#EWA_LF_@sys_frame_unid tr:eq(1)').trigger('mousedown');
        };
        EWA.F.FOS["@sys_frame_unid"].ReloadAfter();
    }
})();

