    var refParas = u1.GetParas();
    var paras = 'EWA_MTYPE=N';
    if (refParas != '') {
        paras += '&' + refParas;
    }
    const isV2025 = u1.GetParameter("IN_BOX_ID");

    var p = isV2025 ? "ENQ_OP_MAIN.F.NM" : "ENQ_OP_MAIN.Frame.NewModify";
    paras += (isV2025 ? "&EWA_IN_DIALOG=1" : "&EWA_REDRAW=1") + "&SUP=@SUP_ID";
    if (ser_ids) {
        paras += "&SER_IDS=" + ser_ids.toURL();
        paras += "&AUTO_JNY=0";
    }
    if (enq_jny_ids) {
        paras += "&ENQ_JNY_ID=" + enq_jny_ids.toURL();
    }
    if (isPkg == "1") {
        paras += "&pkg=1";
    }
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlname', p, false, paras);
}

