Set.Sql:
SELECT '无权删除' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and OWN_SUP_ID!=@G_SUP_ID
;

SELECT '已经是删除状态了' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and ENQ_OP_STATE='DEL'
;

SELECT '已下单，不能删除' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and SELECT_STATE='CHECKED_TRUE'
;

SELECT '已启动流程，不能删除' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and FLOW_STATE!='FLOW_OP'
;

SELECT GRP_FIN_TYPE_ID AS GFTID FROM GRP_FIN_TYPE WHERE GRP_FIN_TYPE_REFID=@ENQ_OP_ID AND GRP_FIN_TYPE_FROM ='ENQ_OP_MAIN';

SELECT TOP 1 '支付申请中，不能删除' FROM GRP_PAY_APPLY WHERE GRP_FIN_TYPE=@GFTID 
and APPLY_STATUS !='DEL';

UPDATE ENQ_OP_MAIN SET ENQ_OP_STATE='DEL' WHERE ENQ_OP_ID = @ENQ_OP_ID;
update SYS_STATUS_IDX set IS_END='Y' where RID=@ENQ_OP_ID and SYS_STA_TABLE='enq_op_main';

DELETE FROM GRP_FIN_TYPE WHERE  GRP_FIN_TYPE_ID=@GFTID;

select '不能替换已下单的采购单对应的支出计划' EWA_ERR_OUT from ENQ_OP_MAIN where ENQ_OP_ID=@OLD_ENQ_OP_ID and SELECT_STATE='CHECKED_TRUE';
select '流程未结束，不能下单' EWA_ERR_OUT from enq_op_main where enq_op_id=@enq_op_id and FLOW_STATE!='FLOW_S_TRUE' ;
UPDATE ENQ_OP_MAIN SET SELECT_STATE='CHECKED_TRUE' WHERE ENQ_OP_ID=@ENQ_OP_ID AND SUP_ID = @SUP_ID ;
-- 记录到 SYS_DATA_LAST表中 用于财务统计表判断是否重新更新 郭磊 2019-03-07 -- 统计应收用已采购(PURCHASE_YES) EXEC PR_SYS_DATA_LAST_TIME 'V_GRP_FIN_SUPPLY', @GRP_ID, 'GRP_ID', @G_SUP_ID, @SYS_DATE;
-- 未采购 未采购(PURCHASE_NO) EXEC PR_SYS_DATA_LAST_TIME 'V_GRP_FIN_UNBUY', @GRP_ID, 'GRP_ID', @G_SUP_ID, @SYS_DATE;
update GRP_FIN_TYPE set GRP_FIN_TYPE_REFID = @ENQ_OP_ID where grp_id=@GRP_ID and RELATE_SUP_ID=@SUP_ID and FIN_TYPE=0 and GRP_FIN_TYPE_FROM ='ENQ_OP_MAIN' and GRP_FIN_TYPE_REFID=@OLD_ENQ_OP_ID and not exists(select 1 from ENQ_OP_MAIN where ENQ_OP_ID=@OLD_ENQ_OP_ID and SELECT_STATE='CHECKED_TRUE')

/* 重置作废询价单，如果日程和服务及人数一致的话，替换成当前的enq_id */
