Set.Sql:
select TOP 1 '采购单['+convert(varchar,A.ENQ_OP_ID)+']有未确认的变更单，请先完成供应商确认后，再执行添加操作' EWA_ERR_OUT from GRP_SER_SP_MAIN A where GRP_ID IN (SELECT GRP_ID FROM ENQ_MAIN c INNER JOIN ENQ_OP_MAIN d on c.ENQ_ID=d.ENQ_ID WHERE d.ENQ_OP_ID=@ENQ_OP_ID) and a.CONFIRM_SUP_ID is null and GSSM_STATUS='USED' ;
select top 1 convert(varchar(10),v.ENQ_JNY_DATE,120)+'：'+SER_KEY_DES+'已存在' EWA_ERR_OUT from ENQ_JNY_SER_SUB a inner join enq_jny c on a.ENQ_JNY_ID = c.ENQ_JNY_ID inner JOIN ENQ_MAIN EM ON a.FRO_ENQ_ID = em.ENQ_ID inner join ENQ_OP_MAIN_SUB s on A.SER_CITY_ID = s.SER_CITY_ID -- 服务所在城市一致 AND A.SER_ID = s.SER_ID -- 服务一致 AND a.ENQ_JNY_SER_SUB_INDEX = s.ENQ_OP_SUB_ID_INDEX -- 服务顺序一致 and c.ENQ_JNY_DAY = s.FRO_ENQ_JNY_DAY and s.FRO_GRP_ID = em.GRP_ID inner join ENQ_OP_MAIN sm on s.ENQ_OP_ID=sm.ENQ_OP_ID inner join V_ENQ_JNY_SER_SUB v on a.ENQ_JNY_SER_SUB_ID = v.ENQ_JNY_SER_SUB_ID inner join ewa_split(@ids,',') x on a.ENQ_JNY_SER_SUB_ID=x.col where isnull(s.SUB_NUM,1)>0 and (sm.SELECT_STATE ='CHECKED_TRUE' OR sm.ENQ_OP_ID=@ENQ_OP_ID) and em.ENQ_ID=@ENQ_ID order by v.ENQ_JNY_DATE ;
select SUP_ID,STATE from ENQ_OP_MAIN where enq_op_id=@enq_op_id;
INSERT INTO ENQ_OP_MAIN_SUB ( enq_op_id, ENQ_JNY_ID, SER_CONN_ID, SER_ID, SUP_ID, ENQ_JNY_PRICE, ENQ_JNY_PRICE_OP, ENQ_JNY_PRICE_SUP, SUP_DOWN_ID, COIN_ID, SUB_UNID, SUB_NUM, SUB_TAG, ENQ_OTHER_SER_ID, CP_TYPE, SER_CITY_ID, SER_KEY0, SER_KEY1, SER_KEY2, COIN_ID_SUP, FROM_ENQ_JNY_SER_SUB_ID, FRO_GRP_ID, FRO_ENQ_ID, FRO_ENQ_JNY_DAY, FRO_ENQ_JNY_DATE, ENQ_OP_SUB_ID_INDEX ) SELECT @enq_op_id, a.ENQ_JNY_ID, A.SER_CONN_ID, A.SER_ID, a.SUP_ID, a.ENQ_JNY_PRICE, a.ENQ_JNY_PRICE_OP, isnull(a.ENQ_JNY_PRICE_SUP,a.ENQ_JNY_PRICE), @SUP_ID, a.COIN_ID, a.SUB_UNID, case when @STATE='ENQ_NEW' then a.SUB_NUM else null end SUB_NUM, a.SUB_TAG, a.ENQ_OTHER_SER_ID, a.CP_TYPE, B.CITY_ID, B.SER_KEY0, B.SER_KEY1, B.SER_KEY2, a.COIN_ID, a.ENQ_JNY_SER_SUB_ID, c.GRP_ID, c.ENQ_ID, c.enq_jny_day, c.enq_jny_date, a.ENQ_JNY_SER_SUB_INDEX -- 当前服务的顺序！！！重要！！！ FROM ENQ_JNY_SER_SUB A INNER JOIN SER_CONN B ON A.SER_CONN_ID = B.SER_CONN_ID inner join enq_jny c on a.ENQ_JNY_ID = c.ENQ_JNY_ID inner JOIN ENQ_MAIN EM ON a.FRO_ENQ_ID = em.ENQ_ID inner join ewa_split(@ids,',') x on a.ENQ_JNY_SER_SUB_ID=x.col where em.ENQ_SELECT_STATE = 'CHECKED_TRUE' and em.ENQ_ID = @ENQ_ID and em.GRP_ID=@GRP_ID and not exists ( select 1 from ENQ_OP_MAIN_SUB s inner join ENQ_OP_MAIN sm on s.ENQ_OP_ID=sm.ENQ_OP_ID where c.ENQ_JNY_DAY = s.FRO_ENQ_JNY_DAY -- 按照天的顺序一致 AND A.SER_CITY_ID = s.SER_CITY_ID -- 服务所在城市一致 AND A.SER_ID = s.SER_ID -- 服务一致 AND a.ENQ_JNY_SER_SUB_INDEX = s.ENQ_OP_SUB_ID_INDEX -- 服务顺序一致 AND s.FRO_GRP_ID = em.GRP_ID --团号一致 AND isnull(s.SUB_NUM,1)>0 AND (sm.SELECT_STATE ='CHECKED_TRUE' OR sm.ENQ_OP_ID=@ENQ_OP_ID) ) ;
SELECT a.ser_ids+isnull(( select ','+convert(varchar,b.ser_id) from ENQ_JNY_SER_SUB b where a.ENQ_ID = b.FRO_ENQ_ID and b.ENQ_JNY_SER_SUB_ID in (select col from ewa_split(@ids,',') x) and b.SER_ID not in (select col from f_split(a.SER_IDS,',')) group by b.SER_ID for xml path('') ),'') new_ser_ids from enq_op_main a where ENQ_OP_ID = @ENQ_OP_ID ;
SELECT a.ENQ_JNY_ID+isnull(( select ','+convert(varchar,b.ENQ_JNY_ID) from ENQ_JNY_SER_SUB b where a.ENQ_ID = b.FRO_ENQ_ID and b.ENQ_JNY_SER_SUB_ID in (select col from ewa_split(@ids,',') x) and b.ENQ_JNY_ID not in (select col from f_split(a.ENQ_JNY_ID,',')) group by b.ENQ_JNY_ID for xml path('') ),'') new_jny_ids from enq_op_main a where ENQ_OP_ID = @ENQ_OP_ID ;
update enq_op_main set ENQ_JNY_ID=@new_jny_ids, SER_IDS=@new_ser_ids where ENQ_OP_ID = @ENQ_OP_ID ;

