(function() {
    const ewa = EWA.F.FOS["@SYS_FRAME_UNID"];

    function getObj(exp) {
        return ewa.getObj(exp);
    }
    ewa.DoPostBefore = function() {
        if (ewa._skipDoPostBefore) {
            ewa._skipDoPostBefore = false;
            return true;
        }
        const ewaFlights = EWA.F.getSubEwas('#flights_@SYS_FRAME_UNID')[0];
        const isok = ewaFlights.submit(function() {
            ewa._skipDoPostBefore = true;
            ewa.DoPost();
        });
        if (!isok) {
            ewa._skipDoPostBefore = false;
            return;
        }
        return true;
    };

    function init() {
        ewa.Merge('ENQ_OP_FIRST_PAY', 'ENQ_OP_FIRST_PAY_DATE', true);
        ewa.Merge('ENQ_OP_SECOND_PAY', 'ENQ_OP_SECOND_PAY_DATE', true);
        let SUB_SUP_ID_NUM = "@SUB_SUP_ID_NUM";
        if (SUB_SUP_ID_NUM > 0) { //地接分公司，合同不是必须
            EWA.F.FOS["@SYS_FRAME_UNID"].setUnMust('PACT_PIC1');
        }

        const u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter("itemname", "2025_ENQ_OP_MAIN_SUB_FLIGHT.LF.edit");
        u1.AddParameter("EWA_CELL_ADD_DES", "1");

        $Install(u1, 'flights_@sys_frame_unid', function() {

        });

        getObj('#ENQ_JNY_PRICE_SUP').on('input', function() {
            const num = getObj('#SUB_NUM').text() * 1;
            const total = getObj('#ALL_PRICE');
            total.val(this.value.replace(/,/ig, '') * num)
        });
        //getObj('#ENQ_JNY_PRICE_SUP').trigger('input');
    }
    init();
})();

