Set.Sql:
SELECT a.*, CASE WHEN PIC_PHY_PATH IS NULL OR PIC_PHY_PATH = '' THEN NULL ELSE @EWA.PATH_UPLOAD_URL + '/' + PIC_PHY_PATH END AS PACT_PIC1, b.SUP_NAME FROM ENQ_OP_MAIN a INNER JOIN sup_main b ON a.sup_id = b.sup_id WHERE a.ENQ_OP_ID = @ENQ_OP_ID AND (a.OWN_SUP_ID = @G_SUP_ID or a.sup_id = @G_SUP_ID);
-- 公司的地接分公司 SELECT count(*) AS SUB_SUP_ID_NUM FROM ADM_USER_GRP_SUB a INNER JOIN ADM_USER_GRP b ON a.AUG_ID = b.AUG_ID AND b.AUG_STATUS = 'COPY' WHERE b.SUP_ID = @G_SUP_ID AND a.SUB_SUP_ID = @SUP_ID;
SELECT sum(ENQ_JNY_PRICE_SUP * sub_num) AS all_price -- 总价 FROM ENQ_OP_MAIN_SUB a INNER JOIN ENQ_OP_MAIN b ON a.ENQ_OP_ID = b.ENQ_OP_ID WHERE b.ENQ_OP_ID = @ENQ_OP_ID AND (b.OWN_SUP_ID = @G_SUP_ID or b.SUP_ID = @G_SUP_ID) ; select * from enq_op_main_sub where enq_op_id = @enq_op_id and ser_id = 1

SELECT '此报价单不属于您，无权操作' AS ewa_err_out FROM ENQ_OP_MAIN WHERE ENQ_OP_ID = @ENQ_OP_ID AND not ( own_sup_id = @g_sup_id OR SUP_ID = @g_sup_id );
UPDATE ENQ_OP_MAIN SET CONFIRM_NO = @CONFIRM_NO, CONFIRM_MEMO = @CONFIRM_NO, CONFIRM_TIME = @SYS_DATE, CONFIRM_ADM_ID = @G_ADM_ID, STATE = 'ENQ_FIN', ALL_PRICE = @ALL_PRICE, ENQ_OP_FIRST_PAY_DATE = @ENQ_OP_FIRST_PAY_DATE, ENQ_OP_FIRST_PAY = @ENQ_OP_FIRST_PAY, ENQ_OP_SECOND_PAY_DATE = @ENQ_OP_SECOND_PAY_DATE, ENQ_OP_SECOND_PAY = @ENQ_OP_SECOND_PAY, ENQ_OP_LAST_PAY_DATE = @ENQ_OP_LAST_PAY_DATE, ENQ_OP_CANCEL_POLICY = @ENQ_OP_CANCEL_POLICY WHERE ENQ_OP_ID = @ENQ_OP_ID AND ( own_sup_id = @g_sup_id OR SUP_ID = @g_sup_id );
SELECT count(*) AS files FROM CURRENCY_FILE A INNER JOIN ENQ_OP_MAIN B ON A.REF_TYPE = 'ENQ_OP_MAIN' AND A.REF_ID = B.ENQ_OP_ID WHERE A.STATE = 'USED' AND A.REF_ID = @ENQ_OP_ID AND ( B.SUP_ID = @G_SUP_ID OR B.own_sup_id = @G_SUP_ID );
-- ewa_test @files = 0 INSERT INTO CURRENCY_FILE ( REF_ID, REF_TYPE, SUP_ID, FILE_TYPE, CURRENCY_REMARK, CURRENCY_SYNC_UNID, ADM_ID, RELATE_SUP_ID, PIC_PHY_PATH, PIC_MD5, CURRENCY_EXT, CURRENCY_OB2, GRP_ID, CURRENCY_OB1 ) SELECT ENQ_OP_ID, 'ENQ_OP_MAIN', A.OWN_SUP_ID, 'PACT1', '采购合同', GETDATE(), A.ADM_ID, A.SUP_ID, PIC_PHY_PATH, PIC_MD5, PIC_EXT, PIC_LEN, C.GRP_ID, '采购合同-' + SUP_NAME + '[' + CAST(ENQ_OP_ID AS VARCHAR(10)) + '].' + ISNULL(PIC_EXT, '') FROM ENQ_OP_MAIN A INNER JOIN SUP_MAIN B ON A.SUP_ID = B.SUP_ID INNER JOIN V_GRP_MAIN C ON A.ENQ_ID = C.ENQ_ID WHERE ENQ_OP_ID = @ENQ_OP_ID AND ISNULL(PIC_PHY_PATH, '') <> '' AND ( own_sup_id = @g_sup_id OR SUP_ID = @g_sup_id );
-- ewa_test @files >0 UPDATE CURRENCY_FILE SET CURRENCY_FILE.PIC_PHY_PATH = A.PIC_PHY_PATH, CURRENCY_FILE.PIC_MD5 = A.PIC_MD5, CURRENCY_EXT = PIC_EXT, CURRENCY_OB1 = '采购合同-' + SUP_NAME + '[' + CAST(ENQ_OP_ID AS VARCHAR(10)) + '].' + ISNULL(PIC_EXT, ''), CURRENCY_OB2 = PIC_LEN FROM ENQ_OP_MAIN A INNER JOIN SUP_MAIN B ON A.SUP_ID = B.SUP_ID WHERE ENQ_OP_ID = @ENQ_OP_ID AND ( A.SUP_ID = @G_SUP_ID OR A.OWN_SUP_ID = @G_SUP_ID ) AND CURRENCY_FILE.[STATE] = 'USED' AND CURRENCY_FILE.REF_TYPE = 'ENQ_OP_MAIN' AND CURRENCY_FILE.REF_ID = @ENQ_OP_ID;
-- ewa_test

