-- 公司的地接分公司 SELECT count(*) AS SUB_SUP_ID_NUM FROM ADM_USER_GRP_SUB a INNER JOIN ADM_USER_GRP b ON a.AUG_ID = b.AUG_ID AND b.AUG_STATUS = 'COPY' WHERE b.SUP_ID = @G_SUP_ID AND a.SUB_SUP_ID = @SUP_ID;
SELECT sum(ENQ_JNY_PRICE_SUP * sub_num) AS all_price -- 总价 FROM ENQ_OP_MAIN_SUB a INNER JOIN ENQ_OP_MAIN b ON a.ENQ_OP_ID = b.ENQ_OP_ID WHERE b.ENQ_OP_ID = @ENQ_OP_ID AND ( b.OWN_SUP_ID = @G_SUP_ID OR b.SUP_ID = @G_SUP_ID )

SELECT '此报价单不属于您，无权操作' AS ewa_err_out FROM ENQ_OP_MAIN WHERE ENQ_OP_ID = @ENQ_OP_ID AND not ( own_sup_id = @g_sup_id OR SUP_ID = @g_sup_id );
UPDATE ENQ_OP_MAIN SET CONFIRM_NO = @CONFIRM_NO, CONFIRM_MEMO = @CONFIRM_MEMO, CONFIRM_TIME = @SYS_DATE, CONFIRM_ADM_ID = @G_ADM_ID, STATE = 'ENQ_FIN', ALL_PRICE = @ALL_PRICE, ENQ_OP_FIRST_PAY_DATE = @ENQ_OP_FIRST_PAY_DATE, ENQ_OP_FIRST_PAY = @ENQ_OP_FIRST_PAY, ENQ_OP_SECOND_PAY_DATE = @ENQ_OP_SECOND_PAY_DATE, ENQ_OP_SECOND_PAY = @ENQ_OP_SECOND_PAY, ENQ_OP_LAST_PAY_DATE = @ENQ_OP_LAST_PAY_DATE, ENQ_OP_CANCEL_POLICY = @ENQ_OP_CANCEL_POLICY, ENQ_OP_QUOTE_STATUS = 'ENQ_QUOTE_PURCHASED' -- 已采购 WHERE ENQ_OP_ID = @ENQ_OP_ID AND ( own_sup_id = @g_sup_id OR SUP_ID = @g_sup_id );
SELECT count(*) AS files FROM CURRENCY_FILE A INNER JOIN ENQ_OP_MAIN B ON A.REF_TYPE = 'ENQ_OP_MAIN' AND A.REF_ID = B.ENQ_OP_ID WHERE A.STATE = 'USED' AND A.REF_ID = @ENQ_OP_ID AND ( B.SUP_ID = @G_SUP_ID OR B.own_sup_id = @G_SUP_ID );
-- ewa_test @files = 0 INSERT INTO CURRENCY_FILE ( REF_ID, REF_TYPE, SUP_ID, FILE_TYPE, CURRENCY_REMARK, CURRENCY_SYNC_UNID, ADM_ID, RELATE_SUP_ID, PIC_PHY_PATH, PIC_MD5, CURRENCY_EXT, CURRENCY_OB2, GRP_ID, CURRENCY_OB1 ) SELECT ENQ_OP_ID, 'ENQ_OP_MAIN', A.OWN_SUP_ID, 'PACT1', '采购合同', GETDATE(), A.ADM_ID, A.SUP_ID, PIC_PHY_PATH, PIC_MD5, PIC_EXT, PIC_LEN, C.GRP_ID, '采购合同-' + SUP_NAME + '[' + CAST(ENQ_OP_ID AS VARCHAR(10)) + '].' + ISNULL(PIC_EXT, '') FROM ENQ_OP_MAIN A INNER JOIN SUP_MAIN B ON A.SUP_ID = B.SUP_ID INNER JOIN V_GRP_MAIN C ON A.ENQ_ID = C.ENQ_ID WHERE ENQ_OP_ID = @ENQ_OP_ID AND ISNULL(PIC_PHY_PATH, '') <> '' AND ( a.own_sup_id = @g_sup_id OR a.SUP_ID = @g_sup_id );
-- ewa_test @files >0 UPDATE CURRENCY_FILE SET CURRENCY_FILE.PIC_PHY_PATH = A.PIC_PHY_PATH, CURRENCY_FILE.PIC_MD5 = A.PIC_MD5, CURRENCY_EXT = PIC_EXT, CURRENCY_OB1 = '采购合同-' + SUP_NAME + '[' + CAST(ENQ_OP_ID AS VARCHAR(10)) + '].' + ISNULL(PIC_EXT, ''), CURRENCY_OB2 = PIC_LEN FROM ENQ_OP_MAIN A INNER JOIN SUP_MAIN B ON A.SUP_ID = B.SUP_ID WHERE ENQ_OP_ID = @ENQ_OP_ID AND ( A.SUP_ID = @G_SUP_ID OR A.OWN_SUP_ID = @G_SUP_ID ) AND CURRENCY_FILE.[STATE] = 'USED' AND CURRENCY_FILE.REF_TYPE = 'ENQ_OP_MAIN' AND CURRENCY_FILE.REF_ID = @ENQ_OP_ID;
-- ewa_test

Set.Bottom:
//ENQ_JNY_SER_SUB_FLIGHT.LF.M
(function() {
    const ewa = EWA.F.FOS['@SYS_FRAME_UNID'];

    function isAlphanumeric(str) {
        // ^ 表示开始，$ 表示结束，[a-zA-Z0-9] 表示只允许英文和数字，+ 表示一个或多个
        return /^[a-zA-Z0-9,/]+$/.test(str);
    }
    ewa.flightSearch = function(obj) {
        const u = new EWA_UrlClass('@ewa.cp/back_admin/apis/flights.jsp');

        const tr = $(obj).parent().parent();

        function getObj1(exp) {
            return tr.find(exp);
        }

        const flightNo = getObj1('#A_CODE').val().trim();
        if (!flightNo) {
            alert('请先输入航班号，例如CA851或MU5130/MU201');
            return;
        }
        if (!isAlphanumeric(flightNo)) {
            alert('航班号输入错误');
            return;
        }
        getObj1('#A_CODE').val(flightNo.toUpperCase());

        u.AddParameter('flight_nos', flightNo);
        const date = getObj1('#EA_ENQ_JNY_DATE').text().trim();
        u.AddParameter('date', date);
        u.AddParameter('departure_city_id', tr[0].dataset.aDCityId);
        u.AddParameter('arrival_city_id', tr[0].dataset.aACityId);
        ewa._searchCompleted = false;
        $Tip('查询机票信息中...', () => {
            return ewa._searchCompleted;
        });
        $J1(u, function(data) {
            ewa._searchCompleted = true;
            if (!data.RST) {
                alert(data.ERR);
                return;
            }
            const flights = data.flights;
            if (!ewa._flightsMap) {
                ewa._flightsMap = {};
            }
            // 用于提交到 ENQ_JNY_SER_SUB_FLIGHT_SEGMENT
            ewa._flightsMap[tr.attr('ewa_key')] = flights;

            // 起飞 & 抵达 IATA（首段出发、末段到达）
            const firstFlight = flights[0];
            const lastFlight = flights[flights.length - 1];

            // 出发/抵达机场代码
            const depIata = firstFlight.d_airport_code; // "PEK"
            const arrIata = lastFlight.a_airport_code; // "LHR"

            // 中转城市（routes 中间部分）
            let transferCities = [];
            if (data.routes && data.routes.length > 2) {
                // routes: ["PEK","HAK","LHR"] → 中转：["HAK"]
                const transitCodes = data.routes.slice(1, -1);
                transferCities = transitCodes.map(code =>
                    (data.citys[code] && data.citys[code].CITY_NAME) || code
                );
            }
            const transferStr = transferCities.join(' → ');

            // 填充函数
            function safeSet(id, value) {
                getObj1('#' + id).val(value);
            }

            // 填充字段
            //safeSet('A_CODE', data.flight_nos); // "HU7382,HU7911"
            safeSet('A_D_TIME', firstFlight.d_scheduled_time); // "08:00"
            safeSet('A_A_TIME', lastFlight.a_scheduled_time); // "19:30"
            safeSet('A_D_AIRPORT', data.iatas[depIata] || depIata); // "首都机场"
            safeSet('A_A_AIRPORT', data.iatas[arrIata] || arrIata); // "希思罗机场"
            safeSet('A_TRANSFOR', transferStr); // "海口"
            safeSet('A_TIME', data.total_time); // "18:30" —— 注意：这是总耗时（含2小时中转）
            // A_DISTANCE 留空（或设为 "-")
            safeSet('A_DISTANCE', '');
            safeSet('A_DESCRIPTION', data.descriptions);

            console.log('✅ 联程航班信息已填充：', data.flight_nos);
        });
    };
    ewa.ReloadAfter = function(httpReferer) {
        autosize(getObj('textarea'));
        const t = getObj('.ewa-col-A_DESCRIPTION textarea');
        t.attr('placeholder', t.parent().attr('ewa_cell_des'))
        const red = "<span style='color:orangered'>*</span>";
        const musts = ['.ewa-col-A_CODE', '.ewa-col-A_D_TIME', '.ewa-col-A_A_TIME', '.ewa-col-A_D_AIRPORT', '.ewa-col-A_A_AIRPORT'];
        getObj(musts.join(',')).prepend(red);

        if ("@ENQ_OP_QUOTE_STATUS" != "") { //ENQ_OP_QUOTE_STATUS
            getObj('input,textarea').prop('disabled', true);
        } else {
            const flightSearch = `<a onclick='EWA.F.FOS["@SYS_FRAME_UNID"].flightSearch(this)'>&nbsp;查询机票信息</a>`
            getObj('.ewa-col-A_CODE').append(flightSearch);
        }
        getObj('.ewa-col-A_CODE input').attr('placeholder', 'CA851或HU7382/HU7911');
        if (window.seviceSelectDialog) {
            // 由于不存在 功能栏，因此强制设置标题
            $(window.seviceSelectDialog.getTitleContainer()).prepend(ewa.Title)
        }
    };

    ewa.submit = function(cb) {
        const musts = {
            'A_CODE': 1,
            'A_D_TIME': 1,
            'A_A_TIME': 1,
            'A_D_AIRPORT': 1,
            'A_A_AIRPORT': 1
        };
        const data = {
            EOMSF_IDS: []
        };
        let isok = true;
        getObj('.ewa-lf-data-row').each(function() {
            data.EOMSF_IDS.push($(this).attr('ewa_key'));
            $(this).find('input,textarea').each(function() {
                const id = this.id;
                const val = this.value.replace(/`/ig, '');
                if (musts[id] && !val) {
                    $Tip('需要输入');
                    $Mark(this);
                    isok = false;
                    return;
                }
                if (!data[id]) {
                    data[id] = [];
                }
                data[id].push(val);
            });
        });

        if (!isok) {
            return;
        }
        if (ewa._flightsMap) {
            for (const sub_eomsf_id in ewa._flightsMap) {
                const flights = ewa._flightsMap[sub_eomsf_id];
                if (!data.sub_eomsf_ids) {
                    data.sub_eomsf_ids = [];
                    data.EAS_SEGMENT_INDEX = [];
                }

                for (let i = 0; i < flights.length; i++) {
                    const flight = flights[i];
                    data.sub_eomsf_ids.push(sub_eomsf_id);
                    data.EAS_SEGMENT_INDEX.push(i);
                    for (const key in flight) {
                        if (!data[key]) {
                            data[key] = [];
                        }
                        data[key].push((flight[key] + "").replace(/`/ig, ''));
                    }
                }
            }
        }
        console.log(data);
        const postData = {};
        Object.keys(data).forEach(key => {
            postData[key] = data[key].join('`');
        });
        console.log(postData);

        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "UAct0");
        u1.AddParameter("ewa_ajax", "json");

        $JP(u1, postData, function(rst) {
            if (cb) {
                cb(rst);
                return;
            }
            // if(!ewa._flightsMap){
            closeDialog();
            return;
            //}
            //创建机票关联时程
            // const u1="@ewa.cp/business/group/create-time-schedule-info-by-flight.jsp?enq_jny_ser_sub_id=@enq_jny_ser_sub_id"+"&enq_jny_id=@enq_jny_id";
            // $J(u1, function(rst){
            //     if(!rst.RST){
            //         alert('创建机票关联时程时错误'+rst.RST);
            //     }
            //     closeDialog();
            // })();
        });
        return true;
    };

    function closeDialog() {
        if (window.seviceSelectDialog) {
            window.seviceSelectDialog.Close();
            window.seviceSelectDialog = null;
            if (EWA.F.FOS["@FROM_PID"]) {
                EWA.F.FOS["@FROM_PID"]._lastFocusEnqJnyId = "@ENQ_JNY_ID";
                EWA.F.FOS["@FROM_PID"].Reload(); //行程列表
            }
        }

    }

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }

    // 执行刷新后事件
    function init() {
        ewa.ReloadAfter();
    }
    init();
})();

