Set.Sql:
UPDATE a SET a.A_CODE = c.col, a.A_D_TIME = d.col, a.A_A_TIME = e.col, a.A_D_AIRPORT = f.col, a.A_A_AIRPORT = g.col, a.A_TRANSFOR = i.col, a.A_TIME = h.col, a.A_DESCRIPTION = j.col FROM ENQ_OP_MAIN_SUB_FLIGHT a INNER JOIN ewa_split (@EOMSF_IDS, '`') b ON a.EOMSF_ID = b.col INNER JOIN ewa_split (@A_CODE, '`') c ON c.idx = b.idx INNER JOIN ewa_split (@A_D_TIME, '`') d ON d.idx = b.idx INNER JOIN ewa_split (@A_A_TIME, '`') e ON e.idx = b.idx INNER JOIN ewa_split (@A_D_AIRPORT, '`') f ON f.idx = b.idx INNER JOIN ewa_split (@A_A_AIRPORT, '`') g ON g.idx = b.idx INNER JOIN ewa_split (@A_TIME, '`') h ON h.idx = b.idx INNER JOIN ewa_split (@A_TRANSFOR, '`') i ON i.idx = b.idx INNER JOIN ewa_split (@A_DESCRIPTION, '`') j ON j.idx = b.idx;
-- ewa_test @sub_EOMSF_IDs is not null DELETE FROM ENQ_OP_MAIN_SUB_FLIGHT_SEGMENT WHERE EOMSF_ID IN ( SELECT col FROM ewa_split (@sub_EOMSF_IDs, '`') a )
INSERT INTO ENQ_OP_MAIN_SUB_FLIGHT_SEGMENT ( EAS_ENQ_JNY_ID, EAS_GRP_ID, EAS_ENQ_ID, EAS_SEGMENT_INDEX, EAS_SEGMENT_LINE, adm_id, sup_id, EOMSF_ID, FLIGHT_NUMBER, AIRLINE, AIRLINE_CODE, D_AIRPORT_CODE, D_AIRPORT_NAME, D_TERMINAL, D_SCHEDULED_TIME, D_ZONE, A_AIRPORT_CODE, A_AIRPORT_NAME, A_TERMINAL, A_SCHEDULED_TIME, A_ZONE, DURATION_SECONDS, DURATION, LAYOVER_SECONDS, LAYOVER_TIME, EAS_CDATE, EAS_STATUS ) SELECT flights.EA_ENQ_JNY_ID, flights.EA_grp_id, flights.EA_enq_id, segment.col, '', @g_adm_id, @g_sup_id, a.col, fn.col AS FLIGHT_NUMBER, al.col AS AIRLINE, left(fn.col,2) AS AIRLINE_CODE, da_code.col AS D_AIRPORT_CODE, da_name.col AS D_AIRPORT_NAME, dt.col AS D_TERMINAL, dst.col AS D_SCHEDULED_TIME, dz.col AS D_ZONE, aa_code.col AS A_AIRPORT_CODE, aa_name.col AS A_AIRPORT_NAME, AT.col AS A_TERMINAL, ast.col AS A_SCHEDULED_TIME, az.col AS A_ZONE, ds.col AS DURATION_SECONDS, dur.col AS DURATION, los.col AS LAYOVER_SECONDS, lot.col AS LAYOVER_TIME, GETDATE() AS EAS_CDATE, 'USED' AS EAS_STATUS FROM ENQ_OP_MAIN_SUB_FLIGHT flights INNER JOIN ewa_split (@sub_EOMSF_IDs, '`') a on a.col = flights.EOMSF_ID INNER JOIN ewa_split (@EAS_SEGMENT_INDEX, '`') segment ON a.idx = segment.idx INNER JOIN ewa_split (@FLIGHT_NUMBER, '`') fn ON a.idx = fn.idx INNER JOIN ewa_split (@AIRLINE, '`') al ON fn.idx = al.idx -- INNER JOIN ewa_split (@AIRLINE_CODE, '`') ac ON fn.idx = ac.idx INNER JOIN ewa_split (@D_AIRPORT_CODE, '`') da_code ON fn.idx = da_code.idx INNER JOIN ewa_split (@D_AIRPORT_NAME, '`') da_name ON fn.idx = da_name.idx INNER JOIN ewa_split (@D_TERMINAL, '`') dt ON fn.idx = dt.idx INNER JOIN ewa_split (@D_SCHEDULED_TIME, '`') dst ON fn.idx = dst.idx INNER JOIN ewa_split (@D_ZONE, '`') dz ON fn.idx = dz.idx -- INNER JOIN ewa_split (@D_CITY_ID, '`') dci ON fn.idx = dci.idx INNER JOIN ewa_split (@A_AIRPORT_CODE, '`') aa_code ON fn.idx = aa_code.idx INNER JOIN ewa_split (@A_AIRPORT_NAME, '`') aa_name ON fn.idx = aa_name.idx INNER JOIN ewa_split (@A_TERMINAL, '`') AT ON fn.idx = AT.idx INNER JOIN ewa_split (@A_SCHEDULED_TIME, '`') ast ON fn.idx = ast.idx INNER JOIN ewa_split (@A_ZONE, '`') az ON fn.idx = az.idx -- INNER JOIN ewa_split (@A_CITY_ID, '`') aci ON fn.idx = aci.idx INNER JOIN ewa_split (@DURATION_SECONDS, '`') ds ON fn.idx = ds.idx INNER JOIN ewa_split (@DURATION, '`') dur ON fn.idx = dur.idx INNER JOIN ewa_split (@LAYOVER_SECONDS, '`') los ON fn.idx = los.idx INNER JOIN ewa_split (@LAYOVER_TIME, '`') lot ON fn.idx = lot.idx -- ewa_test ;

