(function() {
    let ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    //提交后台数据时执行的检查或附加数据处理
    ewa.DoPostBefore = function() {
        let enq_jny_ids = [];
        let enq_jny_ser_sub_ids = [];
        let enq_op_sub_ids = [];
        let modified_statuses = [];
        let enqJnySerSubIndexes = [];
        let enqOpSubIdIndexes = [];
        let memos = [];
        $('#lst_@SYS_FRAME_UNID .ewa-lf-data-row').each(function() {
            let enq_jny_id = this.dataset.enqJnyId;
            let enq_jny_ser_sub_id = this.dataset.enqJnySerSubId;
            let enq_op_sub_id = this.dataset.enqOpSubId;
            let modified_status = this.dataset.modifiedStatus;
            if("@DELETES_SPLIT"){
                modified_status = "DELETE";
            }
            //  相同服务的序号
            let enqJnySerSubIndex = this.dataset.enqJnySerSubIndex;
            // 订单明细的服务序号，和相同服务的序号一致
            let enqOpSubIdIndex = this.dataset.enqOpSubIdIndex;
            console.log(enqOpSubIdIndex)
            if(enq_jny_id == ""){
                enq_jny_id = -1;
            }
            if (enq_jny_ser_sub_id == "") {
                enq_jny_ser_sub_id = -1;
            }
            if (enq_op_sub_id == "") {
                enq_op_sub_id = -1;
            }
            if(enqJnySerSubIndex == ""){
                enqJnySerSubIndex = -1;
            }
            if(enqOpSubIdIndex == ""){
                enqOpSubIdIndex = -1;
            }
            enq_jny_ids.push(enq_jny_id);
            modified_statuses.push(modified_status);
            enq_jny_ser_sub_ids.push(enq_jny_ser_sub_id);
            enq_op_sub_ids.push(enq_op_sub_id);
            enqJnySerSubIndexes.push(enqJnySerSubIndex);
            enqOpSubIdIndexes.push(enqOpSubIdIndex);
        });
        ewa.PostAddData = {
            enq_jny_ids: enq_jny_ids.join('^'),
            enq_jny_ser_sub_ids: enq_jny_ser_sub_ids.join('^'),
            enq_op_sub_ids: enq_op_sub_ids.join('^'),
            modified_statuses: modified_statuses.join('^'),
            memos: createModifiedMemo(true).join('^'),
            enqOpSubIdIndexes: enqOpSubIdIndexes.join('^'),
            enqJnySerSubIndexes: enqJnySerSubIndexes.join('^')
        };
        console.log(ewa.PostAddData);

        return true;
    };

    function createModifiedMemo(isAll) {
        let msg = [];
        $('#lst_@sys_frame_unid .ewa-lf-data-row ').each(function() {
            if("@DELETES_SPLIT"){
                let s = '[取消] ' + $(this).find('#order_date').text() +
                    '的服务：' + $(this).find('#ORDER_DES').text() +
                    '，数量：' + $(this).find('#SUB_NUM_SUP').text();
                msg.push(s);
                return;
            } 

             var eleDes = $(this).find('#modified_status').attr('title');
            if (eleDes == "") { // 无变化
                if(isAll){
                    msg.push("");
                }
                return;
            }

            if (eleDes == 'DELETE') { // 删除服务
                let s = '[取消] ' + $(this).find('#order_date').text() +
                    '的服务：' + $(this).find('#ORDER_DES').text() +
                    '，数量：' + $(this).find('#SUB_NUM_SUP').text();
                msg.push(s);
            } else if (eleDes == 'INSERT') {
                let s = '[新增] ' + $(this).find('#ser_sub_date').text() +
                    '的服务：' + $(this).find('#SER_SUB_DES').text() +
                    '，数量：' + $(this).find('#SUB_NUM').text();
                msg.push(s);
            } else if (eleDes == 'UPDATE') {
                let dateNow = $(this).find('#ser_sub_date').text();
                let dateOld = $(this).find('#order_date').text();
                let numNow = $(this).find('#SUB_NUM').text();
                let numOld = $(this).find('#SUB_NUM_SUP').text();
                let srvNow = $(this).find('#SER_SUB_DES').text();
                let srvOld = $(this).find('#ORDER_DES').text();
                let ss = [];
                if (dateNow != dateOld) {
                    ss.push("日期: 从" + dateOld + "更改到" + dateNow);
                }
                if (numNow != numOld) {
                    ss.push("数量: 从" + numOld + "更改到" + numNow);
                }
                if (srvNow != srvOld) {
                    ss.push("服务: 从" + srvOld + "更改到" + srvNow);
                }
                let s = '[变更] ' + dateNow + '的服务：' + srvNow + "，" + ss.join("，");
                msg.push(s);
            }
        });
        return msg;

    }

    function getObj(exp) {
        return $('#f_@sys_frame_unid').find(exp);
    }

    function init() {
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter("itemname", "ENQ_OP_MAIN_SUB.ListFrame.View");
        u1.AddParameter("only_changes", "1");
        u1.AddParameter("ewa_pagesize", "500");
        u1.AddParameter("ewa_is_split_page", "no");
        u1.AddParameter("ewa_skip_test1", 1);
        u1.RemoveParameter("ewa-in-dialog");
        $Install(u1, 'lst_@sys_frame_unid', function() {
            let msg = createModifiedMemo().join('\n');
            getObj('#GSSM_CONTENT').val(msg);
        });
    }
    init();
})();

