Set.Sql:
SELECT '团已经关闭,不能进行操作' AS EWA_ERR_OUT from grp_main where grp_id=@grp_id and CLAC_STATUS IN('FINALLY_CLOSE','CLOSE') ;
select '询价单已作废，不能做变更单。请先尝试[重置]操作，如果重置失败请重做采购单。' EWA_ERR_OUT from ENQ_OP_Main a inner join enq_main b on a.ENQ_ID = b.ENQ_ID where ENQ_OP_ID=@ENQ_OP_ID and b.ENQ_SELECT_STATE != 'CHECKED_TRUE' ;
select SUP_ID as SUP_DOWN_ID from ENQ_OP_MAIN where ENQ_OP_ID = @ENQ_OP_ID ; INSERT INTO GRP_SER_SP_MAIN ( GRP_ID, ENQ_OP_ID, GSSM_TITLE, GSSM_PRICE_TOTAL, GSSM_CONTENT, GSSM_CDATE, GSSM_STATUS, GSSM_FLOW, SUP_ID, ADM_ID, GSSM_ENQ_JNY_IDS, GSSM_ENQ_OP_SUB_IDS, GSSM_ENQ_JNY_SER_SUB_IDS, SUP_DOWN_ID ) VALUES ( @GRP_ID, @ENQ_OP_ID, @GSSM_TITLE, 0, @GSSM_CONTENT, @SYS_DATE, 'USED', '', @G_SUP_ID, @G_ADM_ID, @ENQ_JNY_IDS, @ENQ_OP_SUB_IDS, @ENQ_JNY_SER_SUB_IDS, @SUP_DOWN_ID ) -- auto GSSM_ID;
INSERT INTO GRP_SER_SP( FRO_TYPE -- 0 , GRP_ID -- 1 , ENQ_ID -- 2 , ENQ_JNY_ID -- 3 , SER_TAG -- 4 , GRP_SER_SP_NUM -- 5 数量 , GRP_SER_SP_TYPE -- 6 , GRP_SER_SP_PRICE -- 7 , COIN_ID -- 8 , FRO_SER_KEY0 -- 9 , FRO_SER_KEY1 -- 10 , FRO_SER_KEY2 -- 11 , FRO_SER_CITY_ID -- 12 , FRO_ENQ_JNY_DATE -- 13 , FRO_ENQ_JNY_DAY -- 14 , FRO_SER_CONN_ID -- 15 , FRO_ENQ_JNY_SER_SUB_ID -- 16 , FRO_SUB_NUM -- 17 , FRO_ENQ_OP_SUB_ID -- 18 , FRO_ENQ_OP_SUB_ID_INDEX -- 19 , FRO_ENQ_JNY_SER_SUB_INDEX -- 20 , FRO_SER_ID -- 21 , FRO_ENQ_OP_ID -- 22 , GSSM_ID, GRP_SER_SP_NAME, GRP_SER_SP_NAME_EN , GRP_SER_SP_REMARK, GRP_SER_SP_REMARK_EN, GRP_SER_SP_FROM, GRP_SER_SP_REFID , SUP_ID, ADM_ID, CREATE_TIME, SUP_DOWN_ID ) select fro_type -- 0 , case when fro_type='DELETE' then d.GRP_ID else a.GRP_ID end GRP_ID -- 1 , case when fro_type='DELETE' then d.ENQ_ID else a.ENQ_ID end ENQ_ID -- 2 , case when fro_type='DELETE' then d.ENQ_JNY_ID else a.ENQ_JNY_ID end enq_jny_id -- 3 , case when fro_type='DELETE' then d.SER_TAG else a.SER_TAG end SER_TAG -- 4 , case when fro_type='INSERT' then a.SUB_NUM when fro_type='UPDATE' then abs(a.SUB_NUM - d.SUB_NUM) when fro_type='DELETE' then d.SUB_NUM else 0 end as GRP_SER_SP_NUM -- 5 数量 , case when fro_type='INSERT' then 'ADD' when fro_type='DELETE' then 'CUT' when fro_type='UPDATE' and a.SER_KEY0 = d.SER_KEY0 and a.SER_KEY1 = d.SER_KEY1 and a.SER_KEY2 = d.SER_KEY2 and a.SUB_NUM - d.SUB_NUM > 0 then 'ADD' when fro_type='UPDATE' and a.SER_KEY0 = d.SER_KEY0 and a.SER_KEY1 = d.SER_KEY1 and a.SER_KEY2 = d.SER_KEY2 and a.SUB_NUM - d.SUB_NUM < 0 then 'CUT' when fro_type='UPDATE' and a.SER_KEY0 = d.SER_KEY0 and a.SER_KEY1 = d.SER_KEY1 and a.SER_KEY2 = d.SER_KEY2 and a.SUB_NUM - d.SUB_NUM = 0 then '---' when fro_type='UPDATE' -- 服务不一致 and isnull(a.enq_jny_price_sup, a.enq_jny_price) - isnull(d.enq_jny_price_sup , d.enq_jny_price) > 0 then 'ADD' when fro_type='UPDATE' -- 服务不一致 and isnull(a.enq_jny_price_sup, a.enq_jny_price) - isnull(d.enq_jny_price_sup , d.enq_jny_price) < 0 then 'CUT' when fro_type='UPDATE' -- 服务不一致 and isnull(a.enq_jny_price_sup, a.enq_jny_price) - isnull(d.enq_jny_price_sup , d.enq_jny_price) = 0 then '---' else '???' end as GRP_SER_SP_TYPE -- 6 , case -- 新增 按照商户的价格 when fro_type = 'INSERT' then isnull(a.enq_jny_price_sup, a.enq_jny_price) -- 删除，按照供应商价格 when fro_type = 'DELETE' then isnull(d.enq_jny_price_sup, d.enq_jny_price) -- 服务一致，仅修改数量，按照供应商价格设定 when fro_type = 'UPDATE' and a.SER_KEY0 = d.SER_KEY0 and a.SER_KEY1 = d.SER_KEY1 and a.SER_KEY2 = d.SER_KEY2 then isnull(d.enq_jny_price_sup, d.enq_jny_price) -- 服务不一致，数量一致，商户价格 - 供应商价格的差异 when a.SUB_NUM = d.SUB_NUM then abs(isnull(d.enq_jny_price_sup , d.enq_jny_price) - isnull(a.enq_jny_price_sup, a.enq_jny_price)) -- 服务不一致，数量不一致，相同数量的总价格差异+变化的商户总价格/新数量 else abs( ( isnull(a.enq_jny_price_sup, a.enq_jny_price) * a.SUB_NUM -- 供应商总价 - isnull(d.enq_jny_price_sup, d.enq_jny_price) * d.SUB_NUM -- 商户价格总价 ) / (a.SUB_NUM - d.SUB_NUM) ) end as GRP_SER_SP_PRICE -- 7 单价 , case when fro_type='DELETE' then d.COIN_ID_SUP else a.COIN_ID end COIN_ID -- 8 , case when fro_type='DELETE' then d.SER_KEY0 else a.SER_KEY0 end FRO_SER_KEY0 -- 9 , case when fro_type='DELETE' then d.SER_KEY1 else a.SER_KEY1 end FRO_SER_KEY1 -- 10 , case when fro_type='DELETE' then d.SER_KEY2 else a.SER_KEY2 end FRO_SER_KEY2 -- 11 , case when fro_type='DELETE' then d.SER_CITY_ID else a.SER_CITY_ID end FRO_SER_CITY_ID -- 12 , case when fro_type='DELETE' then d.ENQ_JNY_DATE else a.ENQ_JNY_DATE end FRO_ENQ_JNY_DATE -- 13 , case when fro_type='DELETE' then d.ENQ_JNY_DAY else a.ENQ_JNY_DAY end FRO_ENQ_JNY_DAY -- 14 , case when fro_type='DELETE' then d.SER_CONN_ID else a.SER_CONN_ID end FRO_SER_CONN_ID -- 15 , case when fro_type='DELETE' then d.FROM_ENQ_JNY_SER_SUB_ID else a.ENQ_JNY_SER_SUB_ID end FRO_ENQ_JNY_SER_SUB_ID -- 16 , case when fro_type='DELETE' then d.SUB_NUM else a.SUB_NUM end as FRO_SUB_NUM -- 17 , d.enq_op_sub_id as FRO_ENQ_OP_SUB_ID -- 18 , c.enqOpSubIdIndex as FRO_ENQ_OP_SUB_ID_INDEX -- 19 , c.enqJnySerSubIndex as FRO_ENQ_JNY_SER_SUB_INDEX -- 20 , isnull(a.ser_id, d.ser_id) as FRO_SER_ID -- 21 , @ENQ_OP_ID as FRO_ENQ_OP_ID -- 22 , @GSSM_ID, des, null , null, null, 'ENQ_OP_MAIN', @enq_op_id , @g_sup_id, @g_adm_id, getdate(), @SUP_DOWN_ID from ( select a.col as enq_jny_ser_sub_id1 , b.col as enq_op_sub_id1 , c.col as des , d.col as fro_type , e.col as enqJnySerSubIndex , f.col as enqOpSubIdIndex from dbo.f_splita(@enq_jny_ser_sub_ids, '^') a inner join dbo.f_splita(@enq_op_sub_ids, '^') b on a.idx = b.idx inner join dbo.f_splita(@memos, '^') c on a.idx = c.idx inner join dbo.f_splita(@modified_statuses, '^') d on a.idx = d.idx inner join dbo.f_splita(@enqJnySerSubIndexes, '^') e on a.idx = e.idx inner join dbo.f_splita(@enqOpSubIdIndexes, '^') f on a.idx = f.idx ) c left join v_enq_jny_ser_sub a on a.ENQ_JNY_SER_SUB_ID = c.enq_jny_ser_sub_id1 and a.SUP_ID = @g_sup_id left join v_enq_op_main_sub d on c.enq_op_sub_id1 = d.enq_op_sub_id and d.enq_op_id = @enq_op_id and d.SUP_ID = @g_sup_id WHERE c.fro_type !='' ; UPDATE GRP_SER_SP_MAIN set GSSM_PRICE_TOTAL = ( select sum(case when GRP_SER_SP_TYPE = 'ADD' then GRP_SER_SP_PRICE else -1 * GRP_SER_SP_PRICE end * GRP_SER_SP_NUM ) from GRP_SER_SP WHERE GSSM_ID = @GSSM_ID ) WHERE GSSM_ID = @GSSM_ID ;

SELECT '团已经关闭,不能进行操作' AS EWA_ERR_OUT from grp_main where grp_id=@grp_id and CLAC_STATUS IN('FINALLY_CLOSE','CLOSE') ;
select '流程已启动不能修改' EWA_ERR_OUT FROM GRP_SER_SP_MAIN WHERE GSSM_ID = @GSSM_ID and GSSM_FLOW !='' ;
UPDATE GRP_SER_SP_MAIN SET GSSM_TITLE = @GSSM_TITLE, GSSM_CONTENT = @GSSM_CONTENT, GSSM_MDATE = @SYS_DATE, ADM_ID = @G_ADM_ID WHERE GSSM_ID = @GSSM_ID AND SUP_ID = @G_SUP_ID and GSSM_FLOW !='' ;

Set.Top:
function setImpJny(){
    if($("#FROM_GRP_ID").val()){
        $("#IMP_JNY").val("DOC");
    }else{
        $("#IMP_JNY").val("");
    }
}

function loadCity() {
  var cid = $X('S_CONTURY').value;
  if (cid == '') {
    return;
  }
  var u = '@EWA.CP/EWA_STYLE/cgi-bin/?xmlname=@xmlname&itemname=@itemname' 
      + '&ewa_action=citys&ewa_ajax=json&cid=' + cid;
  $J(u, loadCity1);
}

var ref_citys = '@city_split'.split(',');
function loadCity1(datas) {
  var map = {};
  for (var i = 0; i < ref_citys.length; i++) {
    var c = ref_citys[i];
    map[c] = true;
  }
  var s1 = [];
  s1.push('<table border=0><tr>');
  for (var i = 0; i < datas.length; i++) {
    var d = datas[i];
    if (i % 6 == 0 && i > 0) {
      s1.push('</tr><tr>');
    }
    var s = '<td><nobr><input name="S_CITYS" value="' + d.CITY_ID + '" type=checkbox ' + (map[d.CITY_ID] ? 'checked': '') + '> ' + d.CITY_NAME + '</nobr></td>';
    s1.push(s);
  }
  s1.push('</tr></table>');
  $X('S_CITYS').innerHTML = s1.join('');
}

