UPDATE ENQ_OP_MAIN_SUB SET ENQ_JNY_PRICE_SUP = @ENQ_JNY_PRICE_SUP WHERE enq_op_id = @enq_op_id AND SUP_DOWN_ID = @g_sup_id AND EXISTS ( SELECT 1 FROM enq_op_main WHERE enq_op_id = @enq_op_id AND isnull(ENQ_OP_QUOTE_STATUS, '') = '' );
-- 转换机票的ser_conn_id, SER_KEY0, 询价是无航班的，变成对应航班服务 UPDATE ENQ_OP_MAIN_SUB SET OLD_SER_CONN_ID = isnull(OLD_SER_CONN_ID, ser_conn_id), OLD_SER_KEY0 = isnull(OLD_SER_KEY0, SER_KEY0), ser_conn_id = @ser_conn_id, ser_key0 = @ser_key0, OLD_REMARK = 'ser_conn_id from ' + convert(varchar, isnull(OLD_SER_CONN_ID, ser_conn_id)) + ' to ' + convert(varchar, @ser_conn_id) + ', ser_key0 from ' + convert(varchar, isnull(OLD_SER_KEY0, SER_KEY0)) + ' to ' + convert(varchar, @ser_key0) WHERE enq_op_id = @enq_op_id AND SUP_DOWN_ID = @g_sup_id AND EXISTS ( SELECT 1 FROM enq_op_main WHERE enq_op_id = @enq_op_id AND isnull(ENQ_OP_QUOTE_STATUS, '') = '' );
UPDATE ENQ_OP_MAIN SET ENQ_OP_QUOTE_ADM = @g_adm_id, ENQ_OP_QUOTE_DATE = @sys_date, ENQ_OP_QUOTE_STATUS = 'ENQ_QUOTE_QUOTED', -- 已报价 ENQ_OP_FIRST_PAY_DATE = @ENQ_OP_FIRST_PAY_DATE, ENQ_OP_FIRST_PAY = @ENQ_OP_FIRST_PAY, ENQ_OP_SECOND_PAY_DATE = @ENQ_OP_SECOND_PAY_DATE, ENQ_OP_SECOND_PAY = @ENQ_OP_SECOND_PAY, ENQ_OP_LAST_PAY_DATE = @ENQ_OP_LAST_PAY_DATE, ENQ_OP_CANCEL_POLICY = @ENQ_OP_CANCEL_POLICY, all_price = ( SELECT ENQ_JNY_PRICE_SUP * sub_num FROM ENQ_OP_MAIN_SUB WHERE enq_op_id = @enq_op_id ) WHERE enq_op_id = @enq_op_id AND SUP_ID = @g_sup_id AND isnull(ENQ_OP_QUOTE_STATUS, '') = ''

