    var u = '@EWA.CP/ewa?XMLNAME=business/system/scm_doc.xml&ITEMNAME=DOC_MAIN_MAP.ListFrame.View&DOC_TMP_TAG=' + docTag +
        '&ENQ_OP_ID=' + ENQ_OP_ID + '&ENQ_ID=' + ENQ_ID + '&GRP_ID=' + GRP_ID + '&SD_ID=' + SUP_ID +
        '&REF_ID=' + ENQ_OP_ID + '&TABLE_NAME=' + tableName +
        '&SUP_ID=' + SUP_ID + '&ENQ_JNY_IDS=' + ENQ_JNY_ID;
    if (top.AddTab && top != window) {
        top.AddTab(u);
    } else {
        window.open(u);
    }
}

