function stanford() {
    var refParas = UrlParas();
    var paras = 'GRP_ID=@GRP_ID&ENQ_ID=@ENQ_ID';
    if (refParas != '') {
        paras += '&' + refParas;
    }
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
        'business|group|stanford.xml', 'STANFORD_ENQ', false, paras);
}
EWA.F.FOS["@SYS_FRAME_UNID"].ext_unselected = function(enq_op_id, sup_id, ORDID) {
    if (!window.confirm("确定要取消下单吗？")) {
        return;
    }
    if (ORDID != null && ORDID != '') {
        alert('此询价为批量生成，不能操作！');
        return;
    }
    let u1 = this.getUrlClass();
    u1.RemoveEwa();
    u1.AddParameter("xmlName", "@xmlName");
    u1.AddParameter("itemname", "@itemname");
    u1.AddParameter("ewa_ajax", "json");
    u1.AddParameter("ewa_action", "unselected");
    u1.AddParameter("ENQ_OP_ID", enq_op_id);
    u1.AddParameter("sup_id", sup_id);


    $J2(u1.GetUrl(), function(rst) {
        console.log(rst);
        if (rst.indexOf("EWA.UI.Msg.ShowError") < 0) {
            EWA.F.FOS["@SYS_FRAME_UNID"].Reload();
        } else {
            eval(rst);
        }

        //EWA.F.FOS["@SYS_FRAME_UNID"].Reload();
        //top.$Tip("已取消，请删除支付计划");
        //let paras="GRP_FIN_TYPE_FROM=ENQ_OP_MAIN&GRP_FIN_TYPE_REFID="+enq_op_id;
        //EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
        //'/business/group/op.xml', 'GRP_FIN_TYPE.F.Remove', false, paras);
    })
}

EWA.F.FOS["@SYS_FRAME_UNID"].ext_update = function(enq_op_id, grp_id, enq_id, sta_in, sta_out, ssta, ORDID) {
    if (ORDID != null && ORDID != '') {
        alert('此询价为批量生成，不能操作！');
        return
    }
    if (sta_in != 'FLOW_OP') {
        alert('流程已经开始，已经不能修改了，若行程发成变化请重新创建新的询价单！');
        return
    }
    if (sta_out != 'ENQ_NEW') {
        alert('询价已经进行，已经不能修改了，若行程发成变化请重新创建新的询价单！');
        return
    }
    if (ssta == 'CHECKED_TRUE') {
        alert('此份询价已经被选中,不能修改，若行程发成变化请重新创建新的询价单！');
        return
    }
    const u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    const isV2025 = u1.GetParameter("IN_BOX_ID");
    const itemname = "2025_ENQ_OP_MAIN.F.NM";
    let paras = 'enq_op_id=' + enq_op_id + '&EWA_MTYPE=M&GRP_ID=' + grp_id + '&enq_id=' + enq_id +
        "&EWA_IN_DIALOG=1";
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlName', itemname, false, paras);
}


EWA.F.FOS["@SYS_FRAME_UNID"].ext_dela = function(enq_op_id, sta_in, sta_out, ssta, ORDID, sup_type, dele) {

    if (ORDID != null && ORDID != '') {
        alert('此询价为批量生成，不能操作！');
        return
    }
    if (sup_type != 'SUP_GRD_ORD') {
        if (sta_in != 'FLOW_OP') {
            alert('流程已经开始，已经不能修改了，若行程发成变化请重新创建新的询价单！');
            return
        }

        //if (sta_out != 'ENQ_NEW') {
        //    alert('询价已经进行，已经不能修改了，若行程发成变化请重新创建新的询价单！');
        //    return
        //}

        if (ssta == 'CHECKED_TRUE') {
            alert('此份询价已经被选中,不能修改，若行程发成变化请重新创建新的询价单！');
            return
        }
    }

    if (sup_type == 'SUP_GRD_ORD' && dele == 'NO_DEL') {
        alert('境外现金询价已经生成条目的不能删除，请联系管理员！');
        return
    }
    var paras = [];
    paras[0] = {
        Name: 'enq_op_id',
        Value: enq_op_id
    };
    EWA.F.FOS['@SYS_FRAME_UNID'].DoAction(this, 'OnFrameDelete', '您确认删除么？', '删除成功,若此询价单已经被选中，请查看支出计划是否需要变更！', paras);
}

EWA.F.FOS["@SYS_FRAME_UNID"].ext_back = function(enq_op_id, enq_id, enq_jny_id, sup_id, ORDID) {
