function changeTabShow(tab, grpId) {
    if ($(tab).hasClass('EWA_GROUP_CNT_TOP1')) {
        return;
    }
    var last = $(tab).parent().find(".EWA_GROUP_CNT_TOP1");
    var last_id = last.attr('rid');
    last.removeClass("EWA_GROUP_CNT_TOP1").addClass("EWA_GROUP_CNT_TOP");
    $('#' + last_id).hide();

    var this_id = $(tab).attr('rid');
    $(tab).addClass("EWA_GROUP_CNT_TOP1").removeClass("EWA_GROUP_CNT_TOP");
    $('#' + this_id).show();
}

function show_enq_op_main_detail(uid, cr, key, nr, evt) {
    var td = nr.cells[0];
    last_td_id = td.id;
    let grpId = cr.dataset.grpId;
    var header = `<div>
        <div rid='${last_td_id}_0' onclick='changeTabShow(this, ${grpId})' class='EWA_GROUP_CNT_TOP1'>价格明细</div>
        <div rid='${last_td_id}_1' onclick='changeTabShow(this,${grpId})' class='EWA_GROUP_CNT_TOP'>变更单</div>
        <div rid='${last_td_id}_2' onclick='changeTabShow(this,${grpId})' class='EWA_GROUP_CNT_TOP'>变更明细</div>
        <div rid='${last_td_id}_3' onclick='changeTabShow(this,${grpId})' class='EWA_GROUP_CNT_TOP'>支付</div>
        <div rid='${last_td_id}_4' onclick='changeTabShow(this,${grpId})' class='EWA_GROUP_CNT_TOP'>支出计划</div>
        <div style='clear:both'></div>
    </div>`;
    var html = `<div id="${last_td_id}_0"></div>
        <div style="display:none" id="${last_td_id}_1"></div>
        <div style="display:none" id="${last_td_id}_2"></div>
        <div style="display:none" id="${last_td_id}_3"></div>
        <div style="display:none" id="${last_td_id}_4"></div>
