function loadActionJson_payments() {
    var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    u1.AddParameter("ewa_action", "payments");
    u1.AddParameter("ewa_ajax", "json");

    var u = u1.GetUrl();
    $J(u, function(rst) {
        let map2 = $J2MAP1(rst, "GRP_FIN_TYPE_REFID");
        let map3 = {};
        for (let m in map2) {
            map3[m] = $J2MAP(map2[m], "COIN_ID");
        }
        let trs = $('#EWA_LF_@SYS_FRAME_UNID>tbody>tr.ewa-lf-data-row');
        for (let i = 0; i < trs.length; i++) {
            let tr = trs.eq(i);
            let key = tr.attr("ewa_key");
            if (!map3[key]) {
                continue;
            }
            let d3 = map3[key];
            let coin_id = tr.find("#COIN_NAME").attr("coin_id");
            let d = d3[coin_id];
            if (d) {
                var diff = d.PAY_PLAN - d.PAY_REAL;
                let s, s1;
                s = "<div>" + (d.PAY_REAL * 1).fm(2) + "</div>";
                s1 = Math.abs(diff) < 0.01 ? "<div>&nbsp;</div>" : "<div title='" + diff.fm(4) + "'>" + (diff).fm(2) + "</div>";
                tr.find('#payment').html(s);
                tr.find('#unpay').html(s1);
            }
        }
    });
}

function loadActionJson_变更服务统计() {
    var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    u1.AddParameter("ewa_action", "变更服务统计");
    u1.AddParameter("ewa_ajax", "json_all");
    var tb = $('#EWA_LF_@SYS_FRAME_UNID');
    var u = u1.GetUrl();
    $J(u, function(rst) {
        var map = {};
        for (var n in rst[0]) {
            var d = rst[0][n]; //数据行
            var sup_id = d.SUP_DOWN_ID;
            if (!map[sup_id]) {
                map[sup_id] = [];
            }
            var s = "<div data-coin-id='" + d.COIN_ID + "'>" + d.GRP_SER_SP_PRICE * 1 + "(" + d.COIN_NAME + ")</div>";
            map[sup_id].push(s);
        }
        for (var sup_id in map) {
            if (map[sup_id])
                tb.find("tr[data-sup-id=" + sup_id + "] #GRP_SER_SP_PRICE").html(map[sup_id].join(""));
        }

        let map2 = {};
        for (var n in rst[1]) {
            var d = rst[1][n]; //数据行
            var sup_id = d.SUP_ID;
            if (!map2[sup_id]) {
                map2[sup_id] = [];
            }
            var s = "<div data-coin-id='" + d.COIN_ID + "'>" + (d.SP_PAY_REAL * 1).fm(2) +
                "(" + d.COIN_NAME + ")</div>";
            map2[sup_id].push(s);
        }
        for (var sup_id in map) {
            if (map2[sup_id])
                tb.find("tr[data-sup-id=" + sup_id + "] #GRP_SER_SP_PAYED").html(map2[sup_id].join(""));
        }

    });
}

