(function() {
    const ewa = EWA.F.FOS['@SYS_FRAME_UNID'];
    //不显示子对象，打开文件
    EWA.F.FOS["@SYS_FRAME_UNID"].AddPreRowCheck = function(tr, key, evt) {
        evt = evt || event;
        var t = evt.target || evt.srcElement;
        return t.id != 'a';
    };

    ewa.addNew_EnqOpMain = function(isPkg, ser_ids, enq_jny_ids) {
        var u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        var refParas = u1.GetParas();
        var paras = 'EWA_MTYPE=N';
        if (refParas != '') {
            paras += '&' + refParas;
        }

        var p = "2025_ENQ_OP_MAIN.F.NM";
        paras += "&EWA_IN_DIALOG=1&SUP=@SUP_ID&EWA_HEIGHT=500";
        if (ser_ids) {
            paras += "&SER_IDS=" + ser_ids.toURL();
            paras += "&AUTO_JNY=0";
        }
        if (enq_jny_ids) {
            paras += "&ENQ_JNY_ID=" + enq_jny_ids.toURL();
        }
        if (isPkg == "1") {
            paras += "&pkg=1";
        }
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlname', p, false, paras);
    };
    ewa.createViewQR = function(enq_op_id, enq_op_unid, sup_id) {
        let targetUrl = "@ewa.cp/back_admin/common/link.jsp?link_type=enq_op_main&enq_op_id=" +
            enq_op_id + "&enq_op_unid=" + enq_op_unid;

        let tip = '供应商报价二维码';
        let u3 = new EWA_UrlClass("/");
        u3.AddParameter("target_url", targetUrl);
        u3.AddParameter("convert_short_url", 1);
        u3.AddParameter("tip", tip);
        u3.AddParameter("img_name", '供应商报价二维码');
        u3.AddParameter("logo", "gyap");
        let paras = u3.GetParas();
        EWA.UI.Dialog.OpenFrame("create_qrcode", "/business/common/tools.xml", "QRCODE.F.N", false, paras);
    };

    if ("@new_ser_id" && "@new_ENQ_JNY_ID") {
        addNew_EnqOpMain(false, "@new_ser_id", "@new_ENQ_JNY_ID");
    }

    if ("@RID") {
        setTimeout(function() {
            $('#EWA_LF_@SYS_FRAME_UNID tr:eq(1)').trigger("mousedown");
        }, 210);
    }


    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }


    ewa.showInvoices = function(enqOpId) {
        let u = "@EWA.CP/ewa?xmlname=/business/common/sysatts.xml&ITEMNAME=SYS_ATTS.LF.Show&f=ENQ_OP_MAIN-INVOICE&rid=" + enqOpId;
        if (top.AddTab) {
            top.AddTab(u);
        } else {
            window.open(u);
        }
    }

    ewa.ext_check = function(enq_op_id, sup_id, enq_id, enq_jny_id, sta_in, sta_out, ssta, SER_IDS, ORDID, stype, oldEnqOpId) {
        if (sta_in != 'FLOW_S_TRUE') {
            alert('内部审核尚未完毕！');
            return
        }
        if (sta_out != 'ENQ_FIN') {
            alert('外部询价尚未完毕！');
            return
        }
        var paras = [];
        paras[0] = {
            Name: 'ENQ_ID',
            Value: enq_id
        };
        paras[1] = {
            Name: 'sup_id',
            Value: sup_id
        };
        paras[2] = {
            Name: 'enq_op_id',
            Value: enq_op_id
        };
        paras[3] = {
            Name: 'GRP_id',
            Value: "@GRP_ID"
        };
        paras[4] = {
            Name: 'ENQ_JNY_IDS',
            Value: enq_jny_id
        };
        paras[5] = {
            Name: 'SER_IDS',
            Value: SER_IDS
        };

        //判断是否为地接单
        var action = 'ExtendAction1';
        if (stype == 'SUP_GRD_ORD') {
            action = 'ExtendAction0';
            EWA.F.FOS['@SYS_FRAME_UNID'].DoAction(this, action, '', '设置成功，同时生成了结算计划！', paras);
        } else {
            if (!oldEnqOpId) { //获取可用的旧的支付计划
                let u1 = ewa.getUrlClass();
                u1.AddParameter("ewa_ajax", "json_all");
                u1.AddParameter("ewa_action", "getEnqOpIds");
                u1.AddParameter("enq_op_id", enq_op_id);
                u1.AddParameter("grp_id", "@GRP_ID");
                u1.AddParameter("sup_id", sup_id);
                u1.AddParameter("ENQ_ID", enq_id);
                let u = u1.GetUrl();
                let args = [];
                for (let i = 0; i < arguments.length - 1; i++) {
                    args.push(arguments[i]);
                }
                $J1(u, function(datas) {
                    if (datas[0].length > 0 && datas[0][0].DUP_SER) {
                        EWA.UI.Msg.ShowError(datas[0][0].DUP_SER);
                        return;
                    }
                    let rst = datas[1];
                    let oldId;
                    if (rst.length == 0) { //没有可用的旧的支付计划
                        oldId = -1
                    } else if (rst.length == 1 && rst[0].HAS_SAME_SER) { //只有一个，且服务有重叠
                        oldId = rst[0].OLD_ENQ_OP_ID;
                    } else {
                        let hasSameSer = 0;
                        for (let i = 0; i < rst.length; i++) {
                            if (rst[i].HAS_SAME_SER) {
                                hasSameSer++;
                                oldId = rst[i].OLD_ENQ_OP_ID
                            }
                        }
                        if (hasSameSer != 1) {
                            oldId = 0;
                        }
                        console.log(hasSameSer);
                    }
                    if (oldId) {
                        exec_ext_check(args, oldId);
                    } else {
                        createSelectEnqOpId(rst, args); //生成选择列表，自己选择
                    }
                })
                return;
            } else if (oldEnqOpId > 0) {
                paras[6] = {
                    Name: "OLD_ENQ_OP_ID",
                    Value: oldEnqOpId
                }
            }
            EWA.F.FOS['@SYS_FRAME_UNID'].DoAction(this, action, '每个供应商的相同服务只能选中一个报价，是否选中此供应商的这份报价？', '设置成功，同时生成了结算计划！', paras);
        }
    }


    function createSelectEnqOpId(rst, args) {
        let h = [];
        let obj = document.createElement("select");
        obj.id = "old_enq_op_id";
        obj.options.add(new Option("--请选择--", ""));
        for (let i = 0; i < rst.length; i++) {
            let d = rst[i];
            let txt = d.OLD_ENQ_OP_ID + "." + d.SER_NAMES;
            obj.options.add(new Option(txt, d.OLD_ENQ_OP_ID));
        }
        obj.options.add(new Option("--创建新的支出计划--", "-1"));
        let box = $("<div style='text-align:center;padding:12px'></div>");
        box.append("<div style='margin:12px auto'>更新已作废采购单生成的支出计划</div>");
        box.append(obj);

        let btn = $("<input style='margin:15px' type='button' value='确定'>");
        box.append("<br>");
        box.append(btn);
        let dia = $DialogHtml(box);

        btn.on("click", function() {
            let oldId = $(this).closest("div").find("select").val();
            if (!oldId) {
                $Tip("请选择");
                return;
            }
            exec_ext_check(args, oldId);
            dia.Close();
        });
    }

    ewa.ReloadAfter = function(httpReferer) {
        // 直接在sql中计算，不用异步计算了
        //loadActionJson_payments();
        //loadActionJson_变更服务统计();
        ewa.Merge('lkUpInvoice', 'INVOICES');
    }
    ewa.ReloadAfter();
})();

