Set.Sql:
SELECT '无权删除' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and OWN_SUP_ID!=@G_SUP_ID
;

SELECT '已经是删除状态了' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and ENQ_OP_STATE='DEL'
;

SELECT '已下单，不能删除' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and SELECT_STATE='CHECKED_TRUE'
;

SELECT '已启动流程，不能删除' ewa_err_out
from ENQ_OP_MAIN  WHERE ENQ_OP_ID = @ENQ_OP_ID and FLOW_STATE!='FLOW_OP'
;

SELECT GRP_FIN_TYPE_ID AS GFTID FROM GRP_FIN_TYPE WHERE GRP_FIN_TYPE_REFID=@ENQ_OP_ID AND GRP_FIN_TYPE_FROM ='ENQ_OP_MAIN';

SELECT TOP 1 '支付申请中，不能删除' FROM GRP_PAY_APPLY WHERE GRP_FIN_TYPE=@GFTID 
and APPLY_STATUS !='DEL';

UPDATE ENQ_OP_MAIN SET ENQ_OP_STATE='DEL' WHERE ENQ_OP_ID = @ENQ_OP_ID;
update SYS_STATUS_IDX set IS_END='Y' where RID=@ENQ_OP_ID and SYS_STA_TABLE='enq_op_main';

DELETE FROM GRP_FIN_TYPE WHERE  GRP_FIN_TYPE_ID=@GFTID;

SELECT '不能替换已下单的采购单对应的支出计划' EWA_ERR_OUT FROM ENQ_OP_MAIN WHERE ENQ_OP_ID = @OLD_ENQ_OP_ID AND SELECT_STATE = 'CHECKED_TRUE';
SELECT '流程未结束，不能下单' EWA_ERR_OUT FROM enq_op_main WHERE enq_op_id = @enq_op_id AND FLOW_STATE != 'FLOW_S_TRUE';
SELECT ser_ids FROM ENQ_OP_MAIN WHERE ENQ_OP_ID = @ENQ_OP_ID AND own_sup_id = @G_SUP_ID;
UPDATE ENQ_OP_MAIN SET SELECT_STATE = 'CHECKED_TRUE' WHERE ENQ_OP_ID = @ENQ_OP_ID AND SUP_ID = @SUP_ID AND own_sup_id = @G_SUP_ID;
-- ewa_test @ser_ids = '1' -- 更新机票信息 2025-12-28 guolei UPDATE enq_jny_ser_sub SET ser_conn_id = a.changed_ser_conn_id, ENQ_JNY_PRICE = CASE WHEN ENQ_JNY_PRICE = 0 THEN price ELSE ENQ_JNY_PRICE END, ENQ_JNY_PRICE_SUP = price FROM ( SELECT a.ser_conn_id AS changed_ser_conn_id, c.ENQ_JNY_PRICE_SUP AS price, c.SER_ID, c.ENQ_JNY_ID, c.FRO_ENQ_JNY_DAY, c.FROM_ENQ_JNY_SER_SUB_ID FROM ser_conn a -- 发布给买方 INNER JOIN ser_conn b ON a.ref_ser_conn_id = b.ser_conn_id INNER JOIN enq_op_main_sub c ON c.ser_conn_id = b.ser_conn_id WHERE a.own_sup_id = @g_sup_id AND c.ENQ_OP_ID = @ENQ_OP_ID ) a WHERE enq_jny_ser_sub.ENQ_JNY_SER_SUB_ID = a.FROM_ENQ_JNY_SER_SUB_ID;
-- ewa_test ewa_test @ser_ids = '1' UPDATE ENQ_JNY_SER_SUB_FLIGHT SET ENQ_JNY_SER_SUB_FLIGHT.A_CODE = A.A_CODE, ENQ_JNY_SER_SUB_FLIGHT.A_IATA = A.A_IATA, ENQ_JNY_SER_SUB_FLIGHT.A_D_TIME = A.A_D_TIME, ENQ_JNY_SER_SUB_FLIGHT.A_A_TIME = A.A_A_TIME, ENQ_JNY_SER_SUB_FLIGHT.A_D_AIRPORT = A.A_D_AIRPORT, ENQ_JNY_SER_SUB_FLIGHT.A_A_AIRPORT = A.A_A_AIRPORT, ENQ_JNY_SER_SUB_FLIGHT.A_D_AIRPORT_ID = A.A_D_AIRPORT_ID, ENQ_JNY_SER_SUB_FLIGHT.A_A_AIRPORT_ID = A.A_A_AIRPORT_ID, ENQ_JNY_SER_SUB_FLIGHT.A_TRANSFOR = A.A_TRANSFOR, ENQ_JNY_SER_SUB_FLIGHT.A_PLANE = A.A_PLANE, ENQ_JNY_SER_SUB_FLIGHT.A_TIME = A.A_TIME, ENQ_JNY_SER_SUB_FLIGHT.A_EAT = A.A_EAT, ENQ_JNY_SER_SUB_FLIGHT.A_REF = A.A_REF, ENQ_JNY_SER_SUB_FLIGHT.A_DISTANCE = A.A_DISTANCE, ENQ_JNY_SER_SUB_FLIGHT.A_DESCRIPTION = A.A_DESCRIPTION, ENQ_JNY_SER_SUB_FLIGHT.A_ID = A.A_ID FROM ( SELECT b.FROM_ENQ_JNY_SER_SUB_ID, c.* FROM enq_op_main a INNER JOIN enq_op_main_sub b ON a.enq_op_id = b.enq_op_id INNER JOIN ENQ_OP_MAIN_SUB_FLIGHT c ON b.ENQ_OP_SUB_ID = c.ENQ_OP_SUB_ID WHERE a.enq_op_id = @enq_op_id and a.own_sup_id = @G_SUP_ID ) a WHERE ENQ_JNY_SER_SUB_FLIGHT.EA_ENQ_JNY_SER_SUB_ID = a.FROM_ENQ_JNY_SER_SUB_ID AND ENQ_JNY_SER_SUB_FLIGHT.A_BEGIN = A.A_BEGIN -- ewa_test ;
-- 记录到 SYS_DATA_LAST表中 用于财务统计表判断是否重新更新 郭磊 2019-03-07 -- 统计应收用已采购(PURCHASE_YES) EXEC PR_SYS_DATA_LAST_TIME 'V_GRP_FIN_SUPPLY', @GRP_ID, 'GRP_ID', @G_SUP_ID, @SYS_DATE;
-- 未采购 未采购(PURCHASE_NO) EXEC PR_SYS_DATA_LAST_TIME 'V_GRP_FIN_UNBUY', @GRP_ID, 'GRP_ID', @G_SUP_ID, @SYS_DATE;
UPDATE GRP_FIN_TYPE SET GRP_FIN_TYPE_REFID = @ENQ_OP_ID WHERE grp_id = @GRP_ID AND RELATE_SUP_ID = @SUP_ID AND FIN_TYPE = 0 AND GRP_FIN_TYPE_FROM = 'ENQ_OP_MAIN' AND GRP_FIN_TYPE_REFID = @OLD_ENQ_OP_ID AND NOT EXISTS ( SELECT 1 FROM ENQ_OP_MAIN WHERE ENQ_OP_ID = @OLD_ENQ_OP_ID AND SELECT_STATE = 'CHECKED_TRUE' )

/* 重置作废询价单，如果日程和服务及人数一致的话，替换成当前的enq_id */
/* PR_ENQ_OP_MIAN_REST (ENQ_ID, ENQ_OP_ID, ENQ_JNY_IDS, SUP_ID, INDEX_OUT) */
/* 2024-07-27 */

PR_ENQ_OP_MIAN_REST_V2024 (@ENQ_OP_ID, @G_SUP_ID, @G_ADM_ID, @MSG_OUT)

PR_AUTO_FIN_TYPE_BY_EOM
