SELECT top 1 '已支付，不能取消下单' EWA_ERR_OUT from GRP_PAY_APPLY gpa inner join GRP_FIN_TYPE gft on gpa.GRP_FIN_TYPE = gft.GRP_FIN_TYPE_ID where gft.GRP_FIN_TYPE_FROM ='ENQ_OP_MAIN' and gft.GRP_FIN_TYPE_REFID=@ENQ_OP_ID and gpa.APPLY_STATUS!='DEL' and isnull(@G_ADM_ID,'') not in ('668','973') -- 靳朝鹏或吕国芳可以取消 ;
SELECT '未选中，无需取消' EWA_ERR_OUT FROM ENQ_OP_MAIN WHERE ENQ_OP_ID=@ENQ_OP_ID AND SUP_ID = @SUP_ID AND ISNULL(SELECT_STATE,'')!='CHECKED_TRUE' ;
UPDATE ENQ_OP_MAIN SET SELECT_STATE='CHECKED_FALSE' WHERE ENQ_OP_ID=@ENQ_OP_ID AND SUP_ID = @SUP_ID AND SELECT_STATE='CHECKED_TRUE' AND OWN_SUP_ID=@G_SUP_ID ;
-- 记录到 SYS_DATA_LAST表中 用于财务统计表判断是否重新更新 郭磊 2019-03-07 -- 统计应收用已采购(PURCHASE_YES) EXEC PR_SYS_DATA_LAST_TIME 'V_GRP_FIN_SUPPLY', @GRP_ID, 'GRP_ID', @G_SUP_ID, @SYS_DATE;
-- 未采购 未采购(PURCHASE_NO) EXEC PR_SYS_DATA_LAST_TIME 'V_GRP_FIN_UNBUY', @GRP_ID, 'GRP_ID', @G_SUP_ID, @SYS_DATE;

