SELECT DISTINCT ser_id FROM enq_jny_ser_sub WHERE fro_enq_id = @enq_id AND sup_id = @g_sup_id AND sup_down_id = @SUPPLY -- ewa_join ser_ids, ser_id ;
SELECT DISTINCT enq_jny_id FROM enq_jny_ser_sub WHERE fro_enq_id = @enq_id AND sup_id = @g_sup_id AND sup_down_id = @SUPPLY -- ewa_join enq_jny_ids, enq_jny_id ;
select 'ENQ_MOTHOD_COOP' as ENQ_MOTHOD

SELECT '团已经关闭,不能进行操作' AS EWA_ERR_OUT from grp_main where grp_id=@grp_id and CLAC_STATUS IN('FINALLY_CLOSE','CLOSE') ; /* select '下单的货币不一致' AS EWA_ERR_OUT WHERE exists( select count(*) FROM ( select distinct coin_id FROM ENQ_JNY_SER_SUB A WHERE a.ser_id IN ( SELECT col FROM dbo.f_split(@ser_ids,',') ) and a.ENQ_JNY_ID IN ( SELECT col FROM dbo.f_split(@enq_jny_id,',') ) ) aa having count(*)>1 ) */ -- ewa_test @ser_ids != '1' -- 20251227 王总要求机票可以先询价 SELECT '当前没有成交的报价单，请审批后再下单' AS EWA_ERR_OUT WHERE NOT EXISTS ( SELECT * FROM ENQ_MAIN em WHERE GRP_ID = @GRP_ID AND ENQ_SELECT_STATE = 'CHECKED_TRUE' ) -- ewa_test ; -- ewa_test @ser_ids != '1' -- 20251227 王总要求机票可以先询价 SELECT '当前报价单和成交的报价单不一致' AS EWA_ERR_OUT FROM enq_main WHERE enq_id = @enq_id AND enq_id NOT IN ( SELECT enq_id FROM ENQ_MAIN em WHERE GRP_ID = @GRP_ID AND ENQ_SELECT_STATE = 'CHECKED_TRUE' ) -- ewa_test ;
/* start 自动创建客户、供应商、联系人和管理员 */ -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' SELECT '新供应商《'+@new_sup_name+'》已经存在, 请选用已合作供应商' AS EWA_ERR_OUT from crm_com a WHERE crm_com_name = @new_sup_name and SUP_ID = @G_SUP_ID ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' INSERT into crm_com (CRM_COM_NAME, CRM_COM_CDATE, ADM_ID, USE_STATE, CRM_COM_COOP_STATUS, SUP_ID , CRM_COM_STATE, CRM_COM_SALE, CRM_COM_NOTE ) VALUES(@new_sup_name, @SYS_DATE, @G_ADM_ID, 'USED', 'COOP_STATUS_NEW', @G_SUP_ID , 'CRM_S_OK', 'CRM_SALE_NEW', '询价单创建待定客户' ) -- auto new_crm_com_id ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' insert into crm_cus (CRM_COM_ID, SUP_ID, CRM_CUS_NAME, CRM_CUS_CDATE, CRM_CUS_MASTER, ADM_ID, CRM_CUS_STATUS) VALUES (@new_crm_com_id, @G_SUP_ID, @new_sup_name.140, @SYS_DATE, 'COM_YES', @G_ADM_ID, 'CRM_CUS_NEW') -- auto new_crm_cus_id ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' exec PR_SUP_MAIN_FROM_CRM_COM @new_crm_com_id, @G_SUP_ID, @G_ADM_ID, 'SUP_TYPE_SUPPLY' ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' -- PR_ADM_FROM_CRM_CUS( CRM_CUS_ID int, ADM_DEP_ID int, SET_ADM_PWD, adm_id int output) exec PR_ADM_FROM_CRM_CUS @NEW_CRM_CUS_ID, null, null, @new_adm_id_output ; -- ewa_test @new_sup_name is not null and @ENQ_OP_IS_COOP != 'COM_YES' select SUP_DOWN_ID as NEW_SUP_ID from crm_conn a WHERE SUP_UP_ID = @G_SUP_ID and crm_com_id = @new_crm_com_id ; -- ewa_test /* end 自动创建客户、供应商、联系人和管理员 */
-- ewa_test @ENQ_MOTHOD = 'ENQ_MOTHOD_COOP' -- 指定供应商下单 INSERT INTO ENQ_OP_MAIN ( ENQ_ID , SUP_ID , ENQ_JNY_ID, OWN_SUP_ID, CREATE_TIME, ADM_ID, SER_IDS , HTML,REMARK,STATE,PACT_HTML,POPLE_NUM,CAR,GUIDE,HOTLE,MEAL,SENIC,FEE , PICK_UP,ALL_PRICE,SHOPPING,PRACE,SPECIAL,SPECIAL_REMARK,SUP_TYPE , ENQ_METHOD,JNY_ADM_ID , ENQ_OP_CONTACT, ENQ_OP_CT_PHONE, ENQ_OP_CT_EMAIL,ENQ_OP_PAY_REMARK,ENQ_OP_SUP_ACC_ID,ENQ_OP_UNID , AUTO_JNY, FRO_GRP_ID ) VALUES ( @ENQ_ID , isnull(@NEW_SUP_ID, @SUP_ID) , @ENQ_JNY_IDS, @G_SUP_ID, @SYS_DATE, @G_ADM_ID, @SER_IDS , @HTML,@REMARK,'ENQ_NEW',@PACT_HTML,@POPLE_NUM,@CAR,@GUIDE,@HOTLE,@MEAL,@SENIC,@FEE , @PICK_UP,@ALL_PRICE,@SHOPPING,@PRACE,@SPECIAL,@SPECIAL_REMARK,@SUP_TYPE , @ENQ_METHOD,@JNY_ADM_ID -- 订单联系人 , @ENQ_OP_CONTACT, @ENQ_OP_CT_PHONE, @ENQ_OP_CT_EMAIL ,@ENQ_OP_PAY_REMARK,@ENQ_OP_SUP_ACC_ID,@SYS_UNID , @AUTO_JNY, @GRP_ID ) -- ewa_test @ENQ_MOTHOD = 'ENQ_MOTHOD_BIDDING' -- 竞价模式 INSERT INTO ENQ_OP_MAIN ( ENQ_ID , SUP_ID , ENQ_JNY_ID, OWN_SUP_ID, CREATE_TIME, ADM_ID, SER_IDS , HTML,REMARK,STATE,PACT_HTML,POPLE_NUM,CAR,GUIDE,HOTLE,MEAL,SENIC,FEE , PICK_UP,ALL_PRICE,SHOPPING,PRACE,SPECIAL,SPECIAL_REMARK,SUP_TYPE , ENQ_METHOD,JNY_ADM_ID , ENQ_OP_UNID , AUTO_JNY, FRO_GRP_ID ) VALUES ( @ENQ_ID , -1 , @ENQ_JNY_IDS, @G_SUP_ID, @SYS_DATE, @G_ADM_ID, @SER_IDS , @HTML,@REMARK,'ENQ_NEW',@PACT_HTML,@POPLE_NUM,@CAR,@GUIDE,@HOTLE,@MEAL,@SENIC,@FEE , @PICK_UP,@ALL_PRICE,@SHOPPING,@PRACE,@SPECIAL,@SPECIAL_REMARK,@SUP_TYPE , @ENQ_METHOD,@JNY_ADM_ID , @SYS_UNID , @AUTO_JNY, @GRP_ID ) -- ewa_test -- auto enq_op_id
;
INSERT INTO ENQ_OP_MAIN_SUB ( enq_op_id, ENQ_JNY_ID, SER_CONN_ID, SER_ID , SUP_ID, SUP_DOWN_ID , ENQ_JNY_PRICE, ENQ_JNY_PRICE_OP, ENQ_JNY_PRICE_SUP , COIN_ID, SUB_UNID, SUB_NUM, SUB_TAG , ENQ_OTHER_SER_ID, CP_TYPE , SER_CITY_ID, SER_KEY0, SER_KEY1, SER_KEY2, COIN_ID_SUP -- 20240727 新增 guolei , FRO_GRP_ID, FRO_ENQ_ID , FRO_ENQ_JNY_DAY -- 订单创建时，原始的第几天 , FRO_ENQ_JNY_DATE-- 订单创建时，原始的日期 , FROM_ENQ_JNY_SER_SUB_ID , ENQ_OP_SUB_ID_INDEX ) SELECT @enq_op_id, a.ENQ_JNY_ID, A.SER_CONN_ID, A.SER_ID , @g_sup_id, case when @ENQ_METHOD = 'ENQ_MOTHOD_BIDDING' then -1 else isnull(@NEW_SUP_ID, @SUP_ID) end , ENQ_JNY_PRICE, ENQ_JNY_PRICE_OP, /*ENQ_JNY_PRICE*/ null , a.COIN_ID, SUB_UNID, SUB_NUM, SUB_TAG , ENQ_OTHER_SER_ID, CP_TYPE , B.CITY_ID, B.SER_KEY0, B.SER_KEY1, B.SER_KEY2, a.COIN_ID , @GRP_ID, @ENQ_ID , c.ENQ_JNY_DAY , c.ENQ_JNY_DATE , a.ENQ_JNY_SER_SUB_ID , a.ENQ_JNY_SER_SUB_INDEX FROM ENQ_JNY_SER_SUB A INNER JOIN SER_CONN B ON A.SER_CONN_ID = B.SER_CONN_ID INNER join enq_jny c on a.enq_jny_id = c.enq_jny_id AND c.ENQ_JNY_ID IN ( SELECT col FROM dbo.f_split(@enq_jny_ids,',') ) WHERE a.ser_id IN (SELECT col FROM dbo.f_split(@ser_ids,',') ) AND a.ENQ_JNY_SER_SUB_ID in (@SUB_IDS_SPLIT) AND ( a.SUP_ID = @g_sup_id or exists ( -- 采购单的执行者（例如：地接） select 1 from SHARE_DATA sd WHERE GRP_ID = @GRP_ID and sd_ref = 'ENQ_OP_MAIN.SUP_ID' and sd_data = @g_sup_id ) ) AND (SUB_TAG = 'AUTO' OR (SUB_TAG IS NULL AND ENQ_OTHER_SER_ID>0)) ; -- 创建航班信息 INSERT INTO ENQ_OP_MAIN_SUB_FLIGHT( ENQ_OP_ID, ENQ_OP_SUB_ID, EA_ENQ_JNY_SER_SUB_ID , A_ID, A_D_CITY_ID, A_A_CITY_ID, A_CODE, A_IATA, A_D_TIME, A_A_TIME , A_D_AIRPORT, A_A_AIRPORT, A_D_AIRPORT_ID, A_A_AIRPORT_ID, A_TRANSFOR , A_PLANE, A_TIME, A_EAT, A_REF, A_DISTANCE, A_DESCRIPTION, A_CDATE , A_STATUS, SUP_ID, ADM_ID, A_SER_CONN_ID, A_BEGIN, A_END , EA_ENQ_JNY_DATE, EA_ENQ_JNY_ID, EA_ENQ_ID, EA_GRP_ID, EA_TMP_ID ) select @enq_op_id, ENQ_OP_SUB_ID, EA_ENQ_JNY_SER_SUB_ID , A_ID, A_D_CITY_ID, A_A_CITY_ID, A_CODE, A_IATA, A_D_TIME, A_A_TIME , A_D_AIRPORT, A_A_AIRPORT, A_D_AIRPORT_ID, A_A_AIRPORT_ID, A_TRANSFOR , A_PLANE, A_TIME, A_EAT, A_REF, A_DISTANCE, A_DESCRIPTION, @SYS_DATE , A_STATUS, @g_sup_id, @g_ADM_ID, A_SER_CONN_ID, A_BEGIN, A_END , EA_ENQ_JNY_DATE, EA_ENQ_JNY_ID, EA_ENQ_ID, EA_GRP_ID, EA_TMP_ID from ENQ_JNY_SER_SUB a inner join ENQ_JNY_SER_SUB_FLIGHT b on a.ENQ_JNY_SER_SUB_ID = b.EA_ENQ_JNY_SER_SUB_ID inner join ENQ_OP_MAIN_SUB c on c.FROM_ENQ_JNY_SER_SUB_ID = a.ENQ_JNY_SER_SUB_ID WHERE c.ENQ_OP_ID = @ENQ_OP_ID

DELETE FROM GRP_FIN_TYPE WHERE GRP_ID = @GRP_ID AND FIN_TYPE = 0 AND RELATE_SUP_ID = @SUP_ID AND GRP_FIN_TYPE_FROM = 'ENQ_OP_MAIN' AND GRP_FIN_TYPE_REFID = @ENQ_OP_ID;
UPDATE ENQ_OP_MAIN_SUB SET enq_jny_price_sup = enq_jny_price WHERE enq_op_id = @enq_op_id ;
INSERT INTO GRP_FIN_TYPE ( GRP_ID, ENQ_ID, SUP_ID, FIN_TYPE_NAME, COS_PRICE, FIN_TYPE, FIN_TYPE_GROUP, RELATE_SUP_ID, TYPE_MEMO, COIN_ID, FLAGS, SALES_ID, GRP_FIN_TYPE_CDATE, GRP_FIN_TYPE_FROM, GRP_FIN_TYPE_REFID, UNID ) SELECT @GRP_ID, @ENQ_ID, @G_SUP_ID, '供应商支付计划', pp, 0, 'FINTYP_IN', @SUP_ID, '向供应商支付服务费：' + sup_name, coin_id, @FLAGS, @G_ADM_ID, GETDATE(), 'ENQ_OP_MAIN', @ENQ_OP_ID, NEWID() FROM ( SELECT -1 AS FF, 999999 AS SS, '总价' AS DD, @SUP_ID AS GG, cast(sum(isnull(isnull(enq_jny_price_sup, enq_jny_price) * sub_num, 0.0)) AS varchar) + '/' + COIN_KEY AS sup_name, a.coin_id, sum(isnull(isnull(enq_jny_price_sup, enq_jny_price) * sub_num, 0.0)) pp FROM ENQ_OP_MAIN_SUB a INNER JOIN sys_coin b ON a.coin_id = b.coin_id WHERE a.enq_jny_id IN ( SELECT col FROM dbo.f_split (@ENQ_JNY_ID, ',') ) AND a.sup_down_id = @SUP_ID AND a.enq_op_id = @enq_op_id GROUP BY a.coin_id, b.COIN_KEY ) AS TEMP -- auto GRP_FIN_TYPE_ID ; INSERT INTO GRP_PAY_APPLY ( APPLY_USER, APPLY_GRP_ID, APPLY_SUP_ID, APPLY_TITLE, APPLY_CONTENT, PAY_SUP_ID, ACCOUNT, APPLY_TIME, APPLY_STATUS, COIN_ID, GRP_ID, GRP_FIN_TYPE, PAY_TYPE, ADM_ID, UNID, COIN_POINT ) SELECT @G_ADM_ID, @GRP_ID, SUP_ID, FIN_TYPE_NAME, TYPE_MEMO, RELATE_SUP_ID, COS_PRICE, GETDATE(), 'VIS_FIN_NO', COIN_ID, @GRP_ID, @GRP_FIN_TYPE_ID, 'PAY_BANK', @G_ADM_ID, UNID, NULL FROM GRP_FIN_TYPE WHERE GRP_FIN_TYPE_ID = @GRP_FIN_TYPE_ID;

Set.Bottom:
var selectedAllCheckbox = {
    init: function(id, isRedraw) {
        var s = "<a><input type='checkbox' onclick=\"selectedAllCheckbox.selAll('" +
            id + "',this)\" id='CK_SEL_ALL_" +
            id + "'><label for='CK_SEL_ALL_" +
            id + "'>全选</label></a>";
        if (isRedraw == "1") {
            $("#" + id).parent().prev().find(".ewa_d1").css("width", "30px").after(s);
        } else {
            $("#" + id).parent().prev().append(s);
        }
        this.initCks(id);
        selectedAllCheckbox.selSig($("input[type='checkbox'][name='" + id + "']")[0]);
    },
    initArr: function(ids, isRedraw) {
        for (var i = 0; i < ids.length; i++) {
            this.init(ids[i], isRedraw);
        }
    },
    initCks: function(id) {
        $("input[type='checkbox'][name='" + id + "']").bind("click",
            function() {
                selectedAllCheckbox.selSig(this);
            }
        );
    },
    selAll: function(id, obj) {
        if (obj.checked) {
            $("input[type='checkbox'][name='" + id + "']").each(
                function() {
                    this.checked = true;
                }
            );
        } else {
            $("input[type='checkbox'][name='" + id + "']").each(
                function() {
                    this.checked = false;
                }
            );
        }
        if (this.selAfter) {
            this.selAfter(id, obj);
        }
    },
    selSig: function(obj) {
        var n = $(obj).attr("name");
        var objs = $("input[type='checkbox'][name='" + n + "']");
        var ckd = 0;
        var uckd = 0;
        for (var i = 0; i < objs.length; i++) {
            if (objs[i].checked) {
                ckd++;
            } else {
                uckd++;
            }
        }
    },
    selAfter: function(id, obj) {
        //全选后执行
        console.log(id)
        let ewa = EWA.F.FOS["@sys_frame_unid"];
        ewa.selectedChange();
    }
};

(function() {
    console.log("@SER_IDS", "@ENQ_JNY_IDS")
    let ewa = EWA.F.FOS["@sys_frame_unid"];
    ewa.DoPostBefore = function() {
        let add_data = {};
        const ewaLf = EWA.F.getSubEwas(getObj('#SER_SUBS'))[0];
        let sub_ids_split = ewaLf.SelectChecked();
        if (sub_ids_split.length == 0) {
            $Tip('没有选择需要提供的服务明细', 3000);
            return;
        }
        if (!ewa.CheckValidAll()) {
            return;
        }
        add_data["sub_ids_split"] = sub_ids_split;
        this.PostAddData = add_data;
        let supId = getObj('#SUP_ID').val();
        if (!supId) {
            let push = "@ewa.cp/robert/sync_b2b/push_sup_main.jsp?sup_id=" + supId + "&op=PUSH";
            $J1(push, function(rst) {
                console.log(rst);
            });
        }


        return true;
    }

    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }

    function getchecked(name) {
        let ss = [];
        getObj('[name=' + name + ']:checked').each(function() {
            ss.push(this.value);
        });
        return ss.join(',');
    }
    ewa.changeSupplyMethod = function() {
        var coop = getObj('.ewa-row-ENQ_MOTHOD input:checked').val();
        if (coop == 'ENQ_MOTHOD_COOP') { //供应商-服务商
            ewa.setMust("ENQ_OP_CONTACT");
            ewa.setMust("ENQ_OP_CT_PHONE");
            ewa.setMust("ENQ_OP_CT_EMAIL");

            getObj('.ewa-row-ENQ_OP_CONTACT').show();
            getObj('.ewa-row-SUP_ID').show();
            getObj('.ewa-row-PROVIDER_SUP_ID').show();
            getObj('.ewa-row-BIDDING_ADM_ID').hide();
            getObj("#BIDDING_ADM_ID").val("");
            return;
        }
        // 竞价模式
        ewa.setUnMust("ENQ_OP_CONTACT");
        ewa.setUnMust("ENQ_OP_CT_PHONE");
        ewa.setUnMust("ENQ_OP_CT_EMAIL");
        ewa.setMust('NEW_SUP_NAME');
        ewa.setMust("BIDDING_ADM_ID");

        getObj('.ewa-row-ENQ_OP_CONTACT').hide();
        getObj('.ewa-row-SUP_ID').hide();
        getObj('.ewa-row-PROVIDER_SUP_ID').hide();
        getObj('.ewa-row-BIDDING_ADM_ID').show();
        getObj("#BIDDING_ADM_ID").val("@BIDDING_ADM_ID");
    };

    function change() {
        const enqJnyIds = getchecked('ENQ_JNY_IDS');
        //console.log(enqJnyIds);
        const serIds = getchecked('SER_IDS');
        //console.log(serIds)
        //刷新服务明细列表
        let p = getObj('#SER_SUBS');
        const ewaLf = EWA.F.getSubEwas(p);
        let url = ewaLf.length == 0 ? ewa.Url : ewaLf.Url;

        const u1 = new EWA_UrlClass(url);
        u1.AddParameter("p_frame_unid", "@sys_frame_unid");
        if ("@EWA_MTYPE" == "M") {
            u1.AddParameter("ITEMNAME", "ENQ_OP_MAIN.ListFrame.Modify");
            u1.AddParameter("RID", "@enq_op_id");
        } else {
            u1.AddParameter("ser_ids_split", serIds);
            u1.AddParameter("enq_jny_ids_split", enqJnyIds);
            u1.AddParameter("ITEMNAME", "2025_ENQ_OP_MAIN.Lf.ENQ_JNY_SER_SUB");
        }
        u1.AddParameter("ewa_skip_test1", 1);
        u1.RemoveParameter("ewa_in_dialog");

        if (ewaLf.length == 0) { //第一次，安装
            p.css('display', 'block').css('overflow', 'auto').css('width', p.parent().width());
            $Install(u1, p, function() {
                if ("@EWA_MTYPE" !== "M") {
                    return;
                }
                p.find('.ewa-lf-header:eq(0),.ewa-lf-search:eq(0),.ewa-lf-data-row:eq(0)').hide();

            });
        } else {
            ewaLf[0].Url = u1.GetUrl();
            ewaLf[0].Reload();
        }
    }
    // 外部调用
    ewa.selectedChange = change;

    let mergeIds = 'ENQ_OP_CONTACT,ENQ_OP_CT_PHONE,ENQ_OP_CT_EMAIL,ENQ_OP_SUP_ACC_ID';
    ewa.merges('ENQ_OP_CONTACT', mergeIds, true);

    selectedAllCheckbox.initArr(["SER_IDS", "ENQ_JNY_IDS"], "@EWA_REDRAW");

    change();

    ewa.changeSupplyMethod();

    getObj('#SER_IDS input').on('change', function() {
        change();
    });
    getObj('#ENQ_MOTHOD input').on('change', function() {
        ewa.changeSupplyMethod();
    });
    getObj('#PROVIDER_SUP_ID').on('change', function() {
        const supId = this.value;
        ewa.refreshDropList('SUP_ID', supId);

        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "getProviderSersAndEnqJnyDays");
        u1.AddParameter("ewa_ajax", "json_all");
        u1.AddParameter("SER_CONN_PROVIDER_SUP_ID", supId);
        let u = u1.GetUrl();
        $J(u, function(rst) {
            const serIds = rst[0];
            const enqJnyIds = rst[1];
            getObj(`#SER_IDS input`).prop('checked', false).prop('disabled', true);
            for (let n in serIds) {
                let d = serIds[n]; //数据行
                getObj(`#SER_IDS input[value=${d.SER_ID}]`).prop('checked', true);
            }
            getObj(`#ENQ_JNY_IDS input`).prop('checked', false).prop('disabled', true);
            for (let n in enqJnyIds) {
                const enqJnyId = enqJnyIds[n].ENQ_JNY_ID;
                getObj(`#ENQ_JNY_IDS input[value=${enqJnyId}]`).prop('checked', true);
            }
            change();
        });
    });
    if ("@ENQ_OP_SUP_ACC_ID" && "@EWA_MTYPE" == "M") {
        setTimeout(function() {
            getObj('#ENQ_OP_SUP_ACC_ID').val("@ENQ_OP_SUP_ACC_ID");
            console.log("@ENQ_OP_SUP_ACC_ID");
        }, 1000);
    }
    // 二维码
    getObj('#butQR').on('click', function() {
        if ("@EWA_MTYPE" == "N") {
            $Tip('请先确认后再点击');
            return;
        }

        let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";
        let targetUrl = "@ewa.cp/back_admin/common/link.jsp?link_type=enq_op_main&enq_op_id=@enq_op_id&enq_op_unid=@enq_op_unid";

        let tip = '供应商报价二维码';
        let u3 = new EWA_UrlClass("/");
        u3.AddParameter("target_url", targetUrl);
        u3.AddParameter("convert_short_url", 1);
        u3.AddParameter("tip", tip);
        u3.AddParameter("img_name", '供应商报价二维码');
        u3.AddParameter("logo", "gyap");
        let paras = u3.GetParas();
        EWA.UI.Dialog.OpenFrame("create_qrcode", "/business/common/tools.xml", "QRCODE.F.N", false, paras);

    });

})();

